INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (5, 'A频道', 'Aチャンネル', 'https://lain.bgm.tv/pic/cover/l/c0/a0/10227_9Y342.jpg', 'completed', '6.9', 12, 12, 24, NULL, '[\"日常\",\"校园\",\"搞笑\",\"治愈\",\"友情\"]', '讲述四位高中女生——天真烂漫的透、冷静可靠的伦、活泼开朗的优子以及天然呆的渚——在校园和日常生活中的温馨搞笑故事。', '2025-01-09', '2025-01-17', '2011-04-07', '[\"福原香織\",\"悠木碧\",\"内山夕実\",\"寿美菜子\",\"又吉愛\",\"斎藤桃子\",\"茅原実里\",\"沢城みゆき\",\"小野大輔\",\"田村睦心\"]', '[\"福原香織\",\"悠木碧\",\"内山夕実\",\"寿美菜子\",\"又吉愛\",\"斎藤桃子\",\"茅原実里\",\"沢城みゆき\",\"小野大輔\",\"田村睦心\",\"福原香织\",\"内山夕实\",\"又吉爱\",\"斋藤桃子\",\"茅原实里\",\"泽城美雪\",\"小野大辅\"]', 1, '2026-02-06 00:04:44', '2026-03-18 17:56:03');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (6, '悠悠式 ', 'ゆゆ式', 'https://lain.bgm.tv/pic/cover/l/93/5c/175533_OMkhK.jpg', 'completed', '7.3', 12, 12, 24, NULL, '[\"日常\",\"校园\",\"喜剧\",\"友情\",\"OVA\",\"治愈\",\"搞笑\",\"萌系\"]', '三名高中女生——野野原柚子、栎井唯和日向缘——在学校的“情报处理部”中度过轻松愉快的日常，她们通过解决各种小问题和互动，展现了青春友谊的温馨与乐趣。', '2024-12-30', '2025-01-13', '2013-04-09', '[\"大久保瑠美\",\"津田美波\",\"種田梨沙\",\"堀江由衣\",\"茅野愛衣\",\"潘めぐみ\",\"清水茉菜\"]', '[\"大久保瑠美\",\"津田美波\",\"種田梨沙\",\"堀江由衣\",\"茅野愛衣\",\"潘めぐみ\",\"清水茉菜\",\"种田梨沙\",\"茅野爱衣\",\"潘惠美\"]', 1, '2026-02-06 00:04:51', '2026-03-18 17:56:06');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (9, 'Slow Start', 'スロウスタート', 'https://lain.bgm.tv/pic/cover/l/bf/97/214671_77174.jpg', 'completed', '7.0', 12, 12, 24, NULL, '[\"日常\",\"校园\",\"治愈\",\"百合\"]', '因生病而休学一年的少女一之濑花名，在高中入学时隐瞒了这一事实，与同学们一起度过温馨的校园生活。', '2025-09-20', '2025-10-07', '2018-01-06', '[\"近藤玲奈\",\"伊藤彩沙\",\"嶺内ともみ\",\"長縄まりあ\",\"M・A・O\",\"内田真礼\",\"沼倉愛美\",\"日笠陽子\",\"小山力也\",\"楠木ともり\"]', '[\"近藤玲奈\",\"伊藤彩沙\",\"嶺内ともみ\",\"長縄まりあ\",\"M・A・O\",\"内田真礼\",\"沼倉愛美\",\"日笠陽子\",\"小山力也\",\"楠木ともり\",\"岭内友美\",\"长绳麻理亚\",\"市道真央\",\"沼仓爱美\",\"日笠阳子\",\"楠木灯\"]', 1, '2026-02-06 00:05:15', '2026-03-18 17:56:09');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (10, '擅长捉弄的高木同学', 'からかい上手の高木さん', 'https://lain.bgm.tv/pic/cover/l/09/16/219200_wFT9i.jpg', 'completed', '7.7', 12, 12, 24, NULL, '[\"校园\",\"恋爱\",\"喜剧\",\"日常\"]', '故事围绕初中生西片和高木展开，高木经常以各种方式捉弄西片，而西片则试图反击但总是失败。两人之间充满青春气息的互动构成了这部温馨有趣的校园喜剧。', '2025-10-19', '2026-02-09', '2018-01-08', '[\"梶裕貴\",\"高橋李依\",\"内田雄馬\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"小岩井ことり\",\"岡本信彦\",\"落合福嗣\",\"田所陽向\"]', '[\"梶裕貴\",\"高橋李依\",\"内田雄馬\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"小岩井ことり\",\"岡本信彦\",\"落合福嗣\",\"田所陽向\",\"梶裕贵\",\"kaji yuki\",\"kaji yūki\",\"高桥李依\",\"takahashi rie\",\"takahashi ri\'e\",\"内田雄马\",\"uchida yuma\",\"uchida yūma\",\"kohara konomi\",\"M·A·O\",\"伊藤彩沙\",\"itō ayasa\",\"小仓唯\",\"ogura yui\",\"小岩井小鸟\",\"koiwai kotori\",\"冈本信彦\",\"okamoto nobuhiko\",\"ochiai fukushi\",\"田所阳向\",\"tadokoro hinata\"]', 1, '2026-02-06 00:05:20', '2026-03-18 17:56:13');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (11, '黑社会的超能力女儿', 'ヒナまつり', 'https://lain.bgm.tv/pic/cover/l/11/f9/225631_0p0sS.jpg', 'completed', '8.1', 12, 12, 24, NULL, '[\"喜剧\",\"日常\",\"超能力\",\"搞笑\"]', '故事讲述高中生一条萤因父亲工作调动搬到乡下，进入一所全校只有5名学生的迷你高中。她与充满个性的同学们一起度过温馨有趣的校园生活，逐渐融入这个小小的社区。', '2025-03-08', '2025-03-12', '2018-04-06', '[\"田中貴子\",\"中島ヨシキ\",\"本渡楓\",\"村川梨衣\",\"日笠陽子\",\"小澤亜李\",\"小山剛志\",\"河西健吾\",\"柴田秀勝\",\"野島健児\"]', '[\"田中貴子\",\"中島ヨシキ\",\"本渡楓\",\"村川梨衣\",\"日笠陽子\",\"小澤亜李\",\"小山剛志\",\"河西健吾\",\"柴田秀勝\",\"野島健児\",\"田中贵子\",\"中岛由贵\",\"本渡枫\",\"日笠阳子\",\"小泽亚李\",\"小山刚志\",\"柴田秀胜\",\"野岛健儿\"]', 1, '2026-02-06 00:05:27', '2026-03-18 17:56:15');
