INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (23, '打了300年的史莱姆，不知不觉就练到了满级 第二季', 'スライム倒して300年、知らないうちにレベルMAXになってました 第2期', 'https://lain.bgm.tv/pic/cover/l/3b/a9/364844_GIb43.jpg', 'completed', '6.9', 12, 12, 24, NULL, '[\"异世界\",\"日常\",\"治愈\",\"奇幻\",\"轻小说改编\",\"喜剧\"]', '在打倒史莱姆300年后，不知不觉中等级达到MAX的魔女阿梓，继续与家人和朋友在高原上过着悠闲的日常生活。', '2025-05-05', '2025-06-23', '2025-04-05', '[\"悠木碧\",\"本渡楓\",\"千本木彩花\",\"田中美海\",\"原田彩楓\",\"和氣あず未\",\"杉山里穂\",\"小倉唯\",\"沼倉愛美\",\"田村ゆかり\"]', '[\"悠木碧\",\"本渡楓\",\"千本木彩花\",\"田中美海\",\"原田彩楓\",\"和氣あず未\",\"杉山里穂\",\"小倉唯\",\"沼倉愛美\",\"田村ゆかり\",\"本渡枫\",\"原田彩枫\",\"和气杏未\",\"杉山里穗\",\"小仓唯\",\"沼仓爱美\",\"田村由香里\"]', 1, '2026-02-06 00:06:44', '2026-03-18 17:56:24');
