INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (26, '测不准的阿波连同学 第二季', '阿波連さんははかれない 第2期', 'https://lain.bgm.tv/pic/cover/l/ed/2b/506922_8sn3u.jpg', 'completed', '7.3', 12, 12, 24, NULL, '[\"校园\",\"恋爱喜剧\",\"日常\",\"搞笑\",\"奇幻\"]', '阿波连玲奈是一个身材娇小、安静寡言、无法很好地控制距离感的女孩，无论是物理距离还是心理距离。男主角来堂是个普通高中生，两人成为同桌后，来堂渐渐习惯了阿波连无厘头的亲近行为，并发现她冰冷外表下的温柔和笨拙。第二季继续讲述两人之间微妙又可爱的日常互动，以及他们与朋友们的有趣故事。', '2025-04-14', '2025-06-23', '2019-08-30', '[\"福島潤\",\"堀江由衣\",\"雨宮天\",\"高橋李依\",\"茅野愛衣\",\"豊崎愛生\",\"原紗友里\",\"稲田徹\",\"長縄まりあ\",\"名塚佳織\"]', '[\"福島潤\",\"堀江由衣\",\"雨宮天\",\"高橋李依\",\"茅野愛衣\",\"豊崎愛生\",\"原紗友里\",\"稲田徹\",\"長縄まりあ\",\"名塚佳織\",\"福岛润\",\"雨宫天\",\"高桥李依\",\"茅野爱衣\",\"丰崎爱生\",\"原纱友里\",\"稻田彻\",\"长绳麻理亚\",\"名冢佳织\"]', 1, '2026-02-06 00:07:09', '2026-03-18 17:56:26');
