INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (44, '请问您今天要来点兔子吗？', 'ご注文はうさぎですか？', 'https://lain.bgm.tv/pic/cover/l/9f/2f/88287_h4xKo.jpg', 'completed', '7.5', 12, 12, 24, NULL, '[\"日常\",\"治愈\",\"萌系\",\"咖啡店\",\"百合\"]', '高中生保登心爱搬到小镇上的咖啡店Rabbit House寄宿，发现店主孙女香风智乃和店员天天座理世都是可爱的女孩。心爱在咖啡店工作，与朋友们一起度过温馨有趣的日常生活。', NULL, '2026-02-09', '2014-04-10', '[\"佐倉綾音\",\"水瀬いのり\",\"種田梨沙\",\"佐藤聡美\",\"内田真礼\",\"徳井青空\",\"村川梨衣\",\"早見沙織\",\"清川元夢\",\"速水奨\"]', '[\"佐倉綾音\",\"水瀬いのり\",\"種田梨沙\",\"佐藤聡美\",\"内田真礼\",\"徳井青空\",\"村川梨衣\",\"早見沙織\",\"清川元夢\",\"速水奨\",\"佐仓绫音\",\"水濑祈\",\"种田梨沙\",\"佐藤聪美\",\"德井青空\",\"早见沙织\",\"清川元梦\",\"速水奖\"]', 1, '2026-02-07 19:32:18', '2026-03-18 17:57:09');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (46, '擅长捉弄的高木同学 第三季', 'からかい上手の高木さん 3', 'https://lain.bgm.tv/pic/cover/l/2d/ad/347887_j0DFj.jpg', 'completed', '8.4', 12, 12, 24, NULL, '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"青春\"]', '第三季继续讲述西片和高木同学的校园日常，高木同学继续以各种方式捉弄西片，而西片则努力想要反击却总是失败，两人之间微妙的关系在轻松有趣的互动中逐渐发展。', NULL, '2026-02-09', '2018-01-08', '[\"梶裕貴\",\"高橋李依\",\"内田雄馬\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"小岩井ことり\",\"岡本信彦\",\"落合福嗣\",\"田所陽向\"]', '[\"梶裕貴\",\"高橋李依\",\"内田雄馬\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"小岩井ことり\",\"岡本信彦\",\"落合福嗣\",\"田所陽向\",\"梶裕贵\",\"kaji yuki\",\"kaji yūki\",\"高桥李依\",\"takahashi rie\",\"takahashi ri\'e\",\"内田雄马\",\"uchida yuma\",\"uchida yūma\",\"kohara konomi\",\"kohara kono\'mi\",\"M·A·O\",\"mao\",\"m・a・o\",\"小仓唯\",\"ogura yui\",\"小岩井小鸟\",\"koiwai kotori\",\"冈本信彦\",\"okamoto nobuhiko\",\"ochiai fukushi\",\"田所阳向\",\"tadokoro hinata\"]', 1, '2026-02-07 19:34:05', '2026-03-18 17:57:12');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (47, '擅长捉弄的高木同学 剧场版', 'からかい上手の高木さん 劇場版', 'https://lain.bgm.tv/pic/cover/l/fd/00/347888_fBpdB.jpg', 'completed', '7.7', 1, 1, 73, NULL, '[\"校园\",\"恋爱\",\"日常\",\"青春\",\"剧场版\",\"治愈\"]', '初中生西片和高木同学之间的甜蜜日常故事，剧场版讲述了他们初中毕业后的故事。', NULL, '2026-02-04', '2022-06-10', '[\"高橋李依\",\"梶裕貴\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"落合福嗣\",\"岡本信彦\",\"内山昂輝\",\"悠木碧\",\"内田雄馬\"]', '[\"高橋李依\",\"梶裕貴\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"落合福嗣\",\"岡本信彦\",\"内山昂輝\",\"悠木碧\",\"内田雄馬\",\"高桥李依\",\"梶裕贵\",\"小仓唯\",\"冈本信彦\",\"内山昂辉\",\"内田雄马\"]', 1, '2026-02-07 19:40:46', '2026-03-18 17:57:14');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (48, '不要欺负我，长瀞同学', NULL, 'http://lain.bgm.tv/pic/cover/l/86/f2/309753_jWjwJ.jpg', 'completed', '6.8', 12, 12, 24, '故事讲述性格内向的学长与活泼外向的学妹长瀞同学之间的校园日常。长瀞同学经常以捉弄和调侃的方式与学长互动，两人在打闹中逐渐发展出微妙的关系。作品以轻松幽默的方式描绘青春期的情感变化，展现了从恶作剧到相互关心的成长过程。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\"]', '讲述一个害羞的学长被活泼的学妹长瀞同学不断戏弄和欺负的校园喜剧故事。', NULL, '2026-02-09', '2021-04-10', '[\"上坂すみれ\",\"山下大輝\",\"Brittany Cox\",\"小松未可子\",\"LilyPichu\",\"鈴木愛奈\",\"井澤詩織\",\"水樹奈々\"]', '[\"上坂すみれ\",\"山下大輝\",\"Brittany Cox\",\"小松未可子\",\"LilyPichu\",\"鈴木愛奈\",\"井澤詩織\",\"水樹奈々\",\"上坂堇\",\"政委\",\"山下大辉\",\"铃木爱奈\",\"井泽诗织\",\"水树奈奈\",\"77\"]', 1, '2026-02-08 01:41:48', '2026-03-18 17:57:17');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (49, '天使降临到我身边！', '', 'http://lain.bgm.tv/pic/cover/l/f3/2d/249637_2r3gw.jpg', 'completed', NULL, 12, 12, 24, '大学生星野宫子性格内向，害怕与人接触。某天，妹妹日向带来了她的同学白咲花来家里玩。宫子对小花一见钟情，为了接近这位“天使”，她开始尝试制作各种点心，并逐渐克服社交恐惧。故事围绕宫子与小花及其他朋友的温馨日常展开，描绘了她们之间纯真美好的友情与成长。', '[\"日常\",\"治愈\",\"校园\",\"百合\",\"喜剧\"]', '大学生宫姐是个极度怕生的宅女，某天妹妹日向带来了她的同学小花。宫姐被小花的可爱外表吸引，想和她做朋友，却因社交恐惧屡屡失败，由此展开了一系列温馨有趣的日常故事。', NULL, '2026-02-09', '2019-01-08', '[\"上田麗奈\",\"指出毬亜\",\"長江里加\",\"鬼頭明里\",\"大和田仁美\",\"大空直美\",\"Lynn\",\"小清水亜美\",\"藤村歩\",\"豊崎愛生\"]', '[\"上田麗奈\",\"指出毬亜\",\"長江里加\",\"鬼頭明里\",\"大和田仁美\",\"大空直美\",\"Lynn\",\"小清水亜美\",\"藤村歩\",\"豊崎愛生\",\"上田丽奈\",\"指出球亚\",\"长江里加\",\"鬼头明里\",\"小清水亚美\",\"藤村步\",\"丰崎爱生\"]', 1, '2026-02-08 01:46:55', '2026-03-18 17:57:19');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (50, '相反的你和我', '相反的你和我', 'https://lain.bgm.tv/pic/cover/l/71/50/525565_OxOv7.jpg', 'watching', NULL, 9, 12, 24, '故事围绕性格完全相反的高中生——内向安静的优等生佐藤和开朗活泼的运动健将铃木展开。两人因意外事件被迫组成学习小组，在相处过程中逐渐发现彼此隐藏的另一面，从最初的互不理解到慢慢接纳对方的差异，发展出一段温暖而特别的友谊。作品细腻描绘了青少年成长中的自我认知与人际关系，展现了性格互补带来的奇妙化学反应。', '[\"校园\",\"日常\",\"青春\",\"友情\"]', NULL, NULL, NULL, '2026-01-11', '[\"坂田将吾\",\"鈴代紗弓\",\"谷口夢奈\",\"平林瑚夏\",\"岩田アンジ\",\"島袋美由利\",\"加藤渉\",\"大森こころ\",\"楠木ともり\",\"佐伯美由紀\"]', '[\"坂田将吾\",\"鈴代紗弓\",\"谷口夢奈\",\"平林瑚夏\",\"岩田アンジ\",\"島袋美由利\",\"加藤渉\",\"大森こころ\",\"楠木ともり\",\"佐伯美由紀\",\"铃代纱弓\",\"谷口梦奈\",\"岩田安琪\",\"岛袋美由利\",\"加藤涉\",\"大森心\",\"楠木灯\",\"佐伯美由纪\"]', 0, '2026-02-08 01:48:45', '2026-03-18 17:57:21');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (53, '玉子市场', NULL, 'http://lain.bgm.tv/pic/cover/l/f8/7f/55113_TR5Is.jpg', 'completed', NULL, 12, 12, NULL, '故事发生在虚构的兔山商店街，主角北白川玉子是一位高中女生，家里经营着一家传统年糕店。她与商店街的邻居们过着平凡而温馨的日常生活，直到一只会说话的鸟——德拉·达高南池的出现，为她的生活带来了意想不到的变化。作品以轻松幽默的笔触描绘了商店街的人情味与青春物语。', '[\"校园\",\"日常\",\"治愈\",\"喜剧\"]', '故事发生在兔子山商店街，围绕玉子、饼藏等年轻人的日常生活展开，描绘了商店街的温暖人情和青春故事。', NULL, NULL, '2013-01-09', '[\"洲崎綾\",\"金子有希\",\"長妻樹里\",\"山崎たくみ\",\"日高里菜\",\"田丸篤志\",\"山下百合恵\",\"藤原啓治\",\"西村知道\",\"立木文彦\"]', '[\"洲崎綾\",\"金子有希\",\"長妻樹里\",\"山崎たくみ\",\"日高里菜\",\"田丸篤志\",\"山下百合恵\",\"藤原啓治\",\"西村知道\",\"立木文彦\",\"洲崎绫\",\"长妻树里\",\"山崎巧\",\"田丸笃志\",\"山下百合惠\",\"藤原启治\"]', 0, '2026-02-09 23:08:18', '2026-03-18 17:57:24');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (54, '轻音少女', NULL, 'http://lain.bgm.tv/pic/cover/l/48/9d/1424_q8FMQ.jpg', 'completed', NULL, 13, 13, NULL, '故事讲述刚进入高中就读的平泽唯，误打误撞加入了面临废社危机的轻音部。她与秋山澪、田井中律、琴吹䌷三位部员，以及后来加入的中野梓，组成了“放学后TEA TIME”乐队。作品描绘了她们从零开始学习乐器、创作歌曲、参加校园祭演出等日常校园生活，展现了少女们通过音乐建立的深厚友谊与成长历程。', '[\"校园\",\"音乐\",\"日常\",\"喜剧\",\"萌系\"]', '四位高中女生组建轻音乐部，从零开始学习乐器并参加校园演出，展现青春友谊与音乐成长的故事。', NULL, '2026-02-09', '2009-04-02', '[\"豊崎愛生\",\"林美秀\",\"日笠陽子\",\"錢欣郁\",\"佐藤聡美\",\"謝佼娟\",\"寿美菜子\",\"傅其慧\",\"竹達彩奈\",\"雷碧文\"]', '[\"豊崎愛生\",\"林美秀\",\"日笠陽子\",\"錢欣郁\",\"佐藤聡美\",\"謝佼娟\",\"寿美菜子\",\"傅其慧\",\"竹達彩奈\",\"雷碧文\",\"丰崎爱生\",\"日笠阳子\",\"钱欣郁\",\"佐藤聪美\",\"谢佼娟\",\"竹达彩奈\"]', 1, '2026-02-09 23:08:27', '2026-03-18 17:57:27');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (55, '轻音少女 第二季', NULL, 'https://cdn.myanimelist.net/images/anime/10/76120l.jpg', 'completed', '7.4', 27, 27, NULL, '樱丘高中轻音部的四位成员——平泽唯、秋山澪、田井中律、琴吹䌷，在成功阻止社团被废部后，迎来了新的学年。她们升入三年级，并迎来了新成员中野梓。故事继续围绕她们的校园生活、音乐练习和日常趣事展开，描绘了五位少女在毕业前共同度过的温馨时光。', '[\"校园\",\"音乐\",\"日常\",\"治愈\",\"搞笑\"]', '樱丘高中轻音部的四位成员——平泽唯、秋山澪、田井中律和琴吹䌷，在升入二年级后迎来了新成员中野梓。她们继续享受着音乐和校园生活，一起练习、举办演唱会、参加学园祭，在欢笑与泪水中度过美好的高中时光。', NULL, '2026-02-09', '2010-04-06', '[\"豊崎愛生\",\"林美秀\",\"日笠陽子\",\"錢欣郁\",\"佐藤聡美\",\"謝佼娟\",\"寿美菜子\",\"傅其慧\",\"竹達彩奈\",\"雷碧文\"]', '[\"豊崎愛生\",\"林美秀\",\"日笠陽子\",\"錢欣郁\",\"佐藤聡美\",\"謝佼娟\",\"寿美菜子\",\"傅其慧\",\"竹達彩奈\",\"雷碧文\",\"丰崎爱生\",\"日笠阳子\",\"钱欣郁\",\"佐藤聪美\",\"谢佼娟\",\"竹达彩奈\"]', 1, '2026-02-09 23:08:36', '2026-03-18 17:57:31');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (56, '擅长捉弄的高木同学 第二季', '擅长捉弄的高木同学 第二季', 'https://lain.bgm.tv/pic/cover/l/f5/c8/271151_UB2n6.jpg', 'completed', '7.4', 12, 12, NULL, '故事继续围绕初中生西片和高木同学的校园生活展开。高木同学依然以各种巧妙的方式捉弄西片，而西片则绞尽脑汁想要反击却总是失败。在轻松愉快的日常互动中，两人之间的感情逐渐加深，展现了青春期的纯真与美好。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\"]', '初中生西片总是被邻座的高木同学捉弄，他试图反击却总是失败。第二季继续讲述两人之间甜蜜有趣的日常互动，西片能否成功捉弄高木一次呢？', NULL, '2026-02-09', '2019-07-07', '[\"梶裕貴\",\"高橋李依\",\"内田雄馬\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"小岩井ことり\",\"岡本信彦\",\"落合福嗣\",\"田所陽向\"]', '[\"梶裕貴\",\"高橋李依\",\"内田雄馬\",\"小原好美\",\"M・A・O\",\"小倉唯\",\"小岩井ことり\",\"岡本信彦\",\"落合福嗣\",\"田所陽向\",\"梶裕贵\",\"kaji yuki\",\"kaji yūki\",\"高桥李依\",\"takahashi rie\",\"takahashi ri\'e\",\"内田雄马\",\"uchida yuma\",\"uchida yūma\",\"kohara konomi\",\"kohara kono\'mi\",\"M·A·O\",\"mao\",\"m・a・o\",\"小仓唯\",\"ogura yui\",\"ogura yūi\",\"小岩井小鸟\",\"koiwai kotori\",\"koiwai koto\'ri\",\"冈本信彦\",\"okamoto nobuhiko\",\"ochiai fukushi\",\"ochiai fuku\'shi\",\"田所阳向\",\"tadokoro hinata\",\"tadokoro hina\'ta\"]', 1, '2026-02-09 23:17:38', '2026-03-18 17:57:35');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (57, '请问您今天要来点兔子吗？ 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/39/a4/123568_FeekE.jpg', 'completed', NULL, 12, 12, NULL, '《请问您今天要来点兔子吗？》第二季延续了第一季的温馨日常风格。故事继续围绕心爱在Rabbit House咖啡厅的生活展开，她与智乃、理世、千夜等朋友们一起度过充满欢笑与感动的每一天。本季中，心爱更加融入小镇生活，与伙伴们共同经历各种有趣的事件，展现了少女们之间深厚的友谊与成长。', '[\"日常\",\"治愈\",\"萌系\",\"咖啡厅\"]', '第二季继续讲述心爱在Rabbit House咖啡厅的温馨日常，与智乃、理世等朋友们的欢乐生活故事。', NULL, '2026-02-09', '2015-10-10', '[\"佐倉綾音\",\"水瀬いのり\",\"種田梨沙\",\"佐藤聡美\",\"内田真礼\",\"徳井青空\",\"村川梨衣\",\"早見沙織\",\"清川元夢\",\"速水奨\"]', '[\"佐倉綾音\",\"水瀬いのり\",\"種田梨沙\",\"佐藤聡美\",\"内田真礼\",\"徳井青空\",\"村川梨衣\",\"早見沙織\",\"清川元夢\",\"速水奨\",\"佐仓绫音\",\"水濑祈\",\"种田梨沙\",\"佐藤聪美\",\"德井青空\",\"早见沙织\",\"清川元梦\",\"速水奖\"]', 1, '2026-02-09 23:17:46', '2026-03-18 17:57:37');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (58, 'SLOW LOOP', NULL, 'http://lain.bgm.tv/pic/cover/l/e8/57/323626_4yEBY.jpg', 'completed', '7.3', 12, 12, NULL, '故事讲述了喜欢独自钓鱼的少女日和，在父亲再婚后与新妹妹小春相遇。小春是个活泼开朗的女孩，对钓鱼一窍不通却充满好奇。两人通过钓鱼这一共同爱好逐渐建立起姐妹情谊，在美丽的海边小镇共同度过温馨日常，分享欢笑与成长的故事。', '[\"日常\",\"治愈\",\"钓鱼\",\"姐妹\",\"校园\"]', '少女小日向光与海野萤因钓鱼相遇，两人性格迥异却因共同的爱好逐渐建立友谊，在宁静的海边小镇展开温馨日常的故事。', NULL, '2026-02-09', '2022-01-07', '[\"久住琳\",\"日岡なつみ\",\"嶺内ともみ\",\"名塚佳織\",\"村上奈津実\",\"井上ほの花\",\"柚木涼香\",\"川田紳司\",\"内匠靖明\",\"勝杏里\"]', '[\"久住琳\",\"日岡なつみ\",\"嶺内ともみ\",\"名塚佳織\",\"村上奈津実\",\"井上ほの花\",\"柚木涼香\",\"川田紳司\",\"内匠靖明\",\"勝杏里\",\"日冈夏美\",\"岭内友美\",\"名冢佳织\",\"村上奈津实\",\"井上穗乃花\",\"柚木凉香\",\"川田绅司\",\"胜杏里\"]', 1, '2026-02-09 23:17:55', '2026-03-18 17:57:41');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (59, '星灵感应', NULL, 'http://lain.bgm.tv/pic/cover/l/e7/be/404115_P7u1Q.jpg', 'completed', NULL, 12, 12, NULL, '故事讲述不擅长与人交流的高中生小之星海果，梦想着前往宇宙。某天她遇见了自称外星人的明内幽，两人开始一起制作火箭。通过这段友谊，海果逐渐打开心扉，与伙伴们共同追寻梦想，是一部温暖治愈的青春校园物语。', '[\"校园\",\"科幻\",\"日常\",\"治愈\"]', '内向的高中生海果与自称外星人的遥相遇，两人共同制作火箭，追寻前往宇宙的梦想，在过程中建立深厚友谊的故事。', NULL, '2026-02-09', '2023-10-09', '[\"船戸ゆり絵\",\"深川芹亜\",\"永牟田萌\",\"青木志貴\",\"高森奈津美\",\"羊宮妃那\",\"白砂沙帆\",\"大野柚布子\",\"川井田夏海\",\"伊藤美来\"]', '[\"船戸ゆり絵\",\"深川芹亜\",\"永牟田萌\",\"青木志貴\",\"高森奈津美\",\"羊宮妃那\",\"白砂沙帆\",\"大野柚布子\",\"川井田夏海\",\"伊藤美来\",\"船户百合绘\",\"深川芹亚\",\"青木志贵\",\"羊宫妃那\"]', 1, '2026-02-09 23:18:03', '2026-03-18 17:57:43');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (60, '这个美术社大有问题！', NULL, 'http://lain.bgm.tv/pic/cover/l/b6/fb/150746_AAL5A.jpg', 'completed', NULL, 12, 12, NULL, '月杜中学美术社只有三名成员：沉迷二次元美少女的社长、毫无干劲的部员宇佐美瑞希，以及拥有惊人绘画天赋却只画理想中二次元新娘的男主内卷昴。故事围绕这个充满问题的美术社展开，描绘了瑞希为了让内卷画现实中的她而不断努力，以及社团日常中的各种趣事。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"社团\"]', '一个普通中学的美术社里，社长沉迷于画二次元老婆，社员们各有各的怪癖，日常充满搞笑与青春烦恼的故事。', NULL, '2026-02-09', '2016-07-07', '[\"小澤亜李\",\"小林裕介\",\"上坂すみれ\",\"東山奈央\",\"利根健太朗\",\"水樹奈々\",\"竹内栄治\",\"掛川裕彦\",\"徳井青空\",\"しもがまちあき\"]', '[\"小澤亜李\",\"小林裕介\",\"上坂すみれ\",\"東山奈央\",\"利根健太朗\",\"水樹奈々\",\"竹内栄治\",\"掛川裕彦\",\"徳井青空\",\"しもがまちあき\",\"小泽亚李\",\"上坂堇\",\"东山奈央\",\"水树奈奈\",\"竹内荣治\",\"挂川裕彦\",\"德井青空\"]', 1, '2026-02-09 23:18:13', '2026-03-18 17:57:47');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (61, '月刊少女野崎君', NULL, 'http://lain.bgm.tv/pic/cover/l/a0/20/100449_d101j.jpg', 'completed', '7.8', 12, 12, NULL, '高中女生佐仓千代鼓起勇气向同年级的野崎梅太郎告白，却意外得到了野崎的亲笔签名和漫画原稿。原来野崎是知名少女漫画家梦野咲子。千代因此成为野崎的漫画助手，与野崎及其朋友们一起参与漫画创作，展开了一系列搞笑又温馨的校园日常故事。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"少女漫画\"]', '高中女生佐仓千代向同班同学野崎梅太郎告白，却意外发现对方是知名少女漫画家，从此成为他的助手，卷入各种搞笑日常。', NULL, '2026-02-09', '2014-07-06', '[\"中村悠一\",\"小澤亜李\",\"岡本信彦\",\"小野友樹\",\"中原麻衣\",\"木村良平\",\"沢城みゆき\",\"三宅健太\",\"小野大輔\",\"川澄綾子\"]', '[\"中村悠一\",\"小澤亜李\",\"岡本信彦\",\"小野友樹\",\"中原麻衣\",\"木村良平\",\"沢城みゆき\",\"三宅健太\",\"小野大輔\",\"川澄綾子\",\"小泽亚李\",\"冈本信彦\",\"小野友树\",\"泽城美雪\",\"小野大辅\",\"川澄绫子\"]', 1, '2026-02-09 23:18:22', '2026-03-18 17:57:50');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (62, '邻家索菲', NULL, 'http://lain.bgm.tv/pic/cover/l/b7/12/241158_H3b25.jpg', 'completed', NULL, 12, 12, NULL, '高中生天野灯偶然发现住在隔壁的索菲其实是吸血鬼。索菲虽然有着吸血鬼的身份，却过着与现代人无异的生活，喜欢收集动漫周边、喝番茄汁代替血液。两人逐渐成为朋友，灯经常拜访索菲家，一起度过温馨有趣的日常时光。作品以轻松幽默的方式描绘人类与吸血鬼之间独特的友谊与生活。', '[\"日常\",\"喜剧\",\"奇幻\",\"治愈\"]', '普通女高中生天野灯偶然遇到吸血鬼索菲，两人成为邻居并开始温馨有趣的同居生活。', NULL, '2026-02-09', '2018-10-05', '[\"富田美憂\",\"篠原侑\",\"Lynn\",\"和氣あず未\",\"日高里菜\",\"内田彩\"]', '[\"富田美憂\",\"篠原侑\",\"Lynn\",\"和氣あず未\",\"日高里菜\",\"内田彩\",\"富田美忧\",\"和气杏未\"]', 1, '2026-02-09 23:20:31', '2026-03-18 17:57:52');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (63, '恋爱小行星', NULL, 'http://lain.bgm.tv/pic/cover/l/eb/9f/276150_tJJGx.jpg', 'completed', '7.6', 12, 12, NULL, '木之幡米拉小时候在露营地遇见了一位自称“天文学者”的男孩，两人约定要一起发现新的小行星。多年后，米拉进入星咲高中，加入了天文部与地质研究会合并而成的“地学部”，在那里她意外重逢了当年那个男孩——真中苍。两人与其他部员一起，在寻找小行星的过程中，共同探索天文与地质的奥秘，并逐渐加深彼此的感情。', '[\"校园\",\"恋爱\",\"日常\",\"社团\",\"天文\"]', '木之幡米拉小时候与一个男孩约定要一起发现小行星，后来加入高中天文社，发现当年那个男孩其实是女孩，两人一起追寻天文梦想的青春故事。', NULL, '2026-02-09', '2020-01-03', '[\"高柳知葉\",\"山口愛\",\"指出毬亜\",\"東山奈央\",\"上坂すみれ\",\"渕上舞\",\"上田麗奈\",\"Lynn\",\"諸星すみれ\",\"小原好美\"]', '[\"高柳知葉\",\"山口愛\",\"指出毬亜\",\"東山奈央\",\"上坂すみれ\",\"渕上舞\",\"上田麗奈\",\"Lynn\",\"諸星すみれ\",\"小原好美\",\"高柳知叶\",\"山口爱\",\"指出球亚\",\"东山奈央\",\"上坂堇\",\"渊上舞\",\"上田丽奈\",\"诸星堇\"]', 1, '2026-02-09 23:20:41', '2026-03-18 17:57:54');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (64, '三者三叶', NULL, 'http://lain.bgm.tv/pic/cover/l/5e/96/145908_S1wd5.jpg', 'completed', '7.1', 12, 12, NULL, '故事围绕三位名字中都带有“叶”字的高中女生展开：活泼开朗的西川叶子、温柔稳重的西山芹奈、以及天然呆萌的叶山照。她们性格迥异却意外成为好友，在校园和日常生活中发生了一系列温馨有趣的日常故事，展现了青春少女之间的友谊与成长点滴。', '[\"校园\",\"日常\",\"喜剧\",\"治愈\"]', '三位名字中都带有“叶”字的高中女生——性格开朗的西川叶子、温柔的大小姐小田切双叶和天然呆的叶山照——的日常校园生活喜剧。', NULL, '2026-02-09', '2016-04-10', '[\"和久井優\",\"金澤まい\",\"今村彩夏\",\"Machico\",\"鈴木愛奈\",\"桃河りか\",\"赤羽根健治\",\"西明日香\",\"渡辺はるか\",\"夏野菜緒\"]', '[\"和久井優\",\"金澤まい\",\"今村彩夏\",\"Machico\",\"鈴木愛奈\",\"桃河りか\",\"赤羽根健治\",\"西明日香\",\"渡辺はるか\",\"夏野菜緒\",\"和久井优\",\"金泽舞\",\"铃木爱奈\",\"桃河里佳\",\"渡边遥\",\"夏野菜绪\"]', 1, '2026-02-09 23:20:48', '2026-03-18 17:57:57');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (65, '飞翔的魔女', NULL, 'http://lain.bgm.tv/pic/cover/l/a5/25/141799_81ZfO.jpg', 'completed', NULL, 12, 12, NULL, '木幡真琴是一名15岁的见习魔女，按照魔女界的传统，她必须离开家乡独自生活一年。她带着黑猫奇多来到青森县弘前市，与远房亲戚圭和千夏同住。在适应新环境的过程中，真琴一边学习魔法，一边体验普通高中生的日常生活，与朋友们共同经历温馨有趣的日常故事。', '[\"日常\",\"奇幻\",\"治愈\",\"校园\"]', '15岁的见习魔女木幡真琴从横滨搬到青森，与表弟圭一起生活，在乡下展开日常魔法生活的故事。', NULL, NULL, '2016-04-09', '[\"篠田みなみ\",\"菅原慎介\",\"鈴木絵理\",\"茅野愛衣\",\"日野まり\",\"三上枝織\",\"葵井歌菜\",\"井口裕香\",\"佐倉綾音\",\"小澤亜李\"]', '[\"篠田みなみ\",\"菅原慎介\",\"鈴木絵理\",\"茅野愛衣\",\"日野まり\",\"三上枝織\",\"葵井歌菜\",\"井口裕香\",\"佐倉綾音\",\"小澤亜李\",\"篠田南\",\"铃木绘理\",\"茅野爱衣\",\"日野真理\",\"三上枝织\",\"佐仓绫音\",\"小泽亚李\"]', 1, '2026-02-09 23:23:56', '2026-03-18 17:58:00');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (66, '悠哉日常大王', NULL, 'http://lain.bgm.tv/pic/cover/l/47/fa/78405_dodKZ.jpg', 'completed', NULL, 12, 12, NULL, '故事发生在远离都市喧嚣的乡村旭丘分校，这里只有五名学生。作品以轻松幽默的笔触描绘了少女们悠闲自在的日常生活，展现了她们在四季更迭中与自然和谐共处的点滴趣事。从田间劳作到校园活动，从节日庆典到日常嬉戏，每个平凡瞬间都充满了温暖与治愈。', '[\"日常\",\"治愈\",\"校园\",\"乡村\"]', '讲述在远离都市的乡村学校中，仅有的五名学生和一位老师之间发生的悠闲日常故事。', NULL, NULL, '2013-10-07', '[\"小岩井ことり\",\"村川梨衣\",\"佐倉綾音\",\"阿澄佳奈\",\"佐藤利奈\",\"名塚佳織\",\"？？？\",\"福圓美里\",\"新谷良子\",\"平松晶子\"]', '[\"小岩井ことり\",\"村川梨衣\",\"佐倉綾音\",\"阿澄佳奈\",\"佐藤利奈\",\"名塚佳織\",\"？？？\",\"福圓美里\",\"新谷良子\",\"平松晶子\",\"小岩井小鸟\",\"佐仓绫音\",\"名冢佳织\",\"福圆美里\"]', 1, '2026-02-09 23:24:04', '2026-03-18 17:58:03');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (67, '悠哉日常大王 Repeat', NULL, 'http://lain.bgm.tv/pic/cover/l/8b/6b/101442_EM1Vg.jpg', 'completed', '7.9', 12, 12, NULL, '《悠哉日常大王》第二季动画，继续讲述旭丘分校的乡村日常故事。宫内莲华、一条萤、越谷夏海、越谷小鞠等角色在宁静的乡村中度过悠闲时光，通过季节变换展现她们纯真的友谊与成长点滴。本季延续了前作的温馨治愈风格，以细腻的日常描写和幽默情节呈现田园生活的美好。', '[\"日常\",\"治愈\",\"校园\",\"喜剧\",\"乡村\"]', '在宁静的乡村，一群小学生继续着悠闲的日常生活，体验季节变化和简单乐趣。', NULL, NULL, '2015-07-06', '[\"小岩井ことり\",\"村川梨衣\",\"佐倉綾音\",\"阿澄佳奈\",\"佐藤利奈\",\"名塚佳織\",\"？？？\",\"福圓美里\",\"新谷良子\",\"平松晶子\"]', '[\"小岩井ことり\",\"村川梨衣\",\"佐倉綾音\",\"阿澄佳奈\",\"佐藤利奈\",\"名塚佳織\",\"？？？\",\"福圓美里\",\"新谷良子\",\"平松晶子\",\"小岩井小鸟\",\"小岩井琴梨\",\"佐仓绫音\",\"名冢佳织\",\"福圆美里\"]', 1, '2026-02-09 23:24:12', '2026-03-18 17:58:05');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (69, '迷糊餐厅 第一季', NULL, 'https://cdn.myanimelist.net/images/anime/10/75262l.jpg', 'completed', NULL, 13, 13, NULL, '故事发生在家庭餐厅“瓦古娜利亚”，以一群性格各异的员工为中心展开的日常喜剧。高中生小鸟游宗太因个子矮小常被误认为小学生，在餐厅打工时遇到了天然呆的宫越华、暴力倾向的种岛白杨、恐男症的伊波真昼等个性鲜明的同事。作品通过轻松幽默的方式描绘他们在餐厅工作中发生的各种趣事，展现青春与成长的温馨故事。', '[\"喜剧\",\"日常\",\"职场\",\"校园\",\"恋爱\"]', '故事发生在家庭餐厅瓦古娜利亚，围绕着一群性格各异的员工展开，包括个子矮小却努力工作的种岛白杨、害怕男性的伊波真昼、外表凶恶内心温柔的山田葵等，描绘他们在工作中的日常趣事和互动。', NULL, NULL, '2010-04-04', '[]', NULL, 1, '2026-02-09 23:24:29', '2026-03-18 17:58:09');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (70, '迷糊餐厅 第二季', NULL, 'https://cdn.myanimelist.net/images/anime/3/75263l.jpg', 'completed', '7.4', 13, 13, NULL, '故事继续发生在家庭餐厅“瓦古娜利亚”，围绕着一群性格各异的员工展开。小鸟游宗太继续应对着前辈们各种奇怪的要求，而种岛白杨、伊波真昼、轰八千代等角色也带来了更多爆笑日常。本季中，员工们的关系进一步发展，既有温馨的互动，也有令人捧腹的误会，展现了餐厅里独特的人际关系和欢乐氛围。', '[\"喜剧\",\"日常\",\"职场\",\"恋爱\"]', '故事继续发生在家庭餐厅瓦古娜利亚，围绕着一群性格各异的员工们展开的日常喜剧。第二季延续了轻松幽默的风格，展现了更多角色之间的互动和成长。', NULL, NULL, '2011-10-01', '[\"福山潤\",\"小野大輔\",\"神谷浩史\",\"阿澄佳奈\",\"藤田咲\",\"喜多村英梨\",\"渡辺久美子\",\"広橋涼\",\"中田譲治\",\"川瀬晶子\"]', '[\"福山潤\",\"小野大輔\",\"神谷浩史\",\"阿澄佳奈\",\"藤田咲\",\"喜多村英梨\",\"渡辺久美子\",\"広橋涼\",\"中田譲治\",\"川瀬晶子\",\"福山润\",\"小野大辅\",\"渡边久美子\",\"广桥凉\",\"中田让治\",\"川濑晶子\"]', 1, '2026-02-09 23:24:38', '2026-03-18 17:58:14');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (71, '迷糊餐厅 第三季', '迷糊餐厅 第三季', 'https://lain.bgm.tv/pic/cover/l/59/dc/110648_52R1q.jpg', 'completed', NULL, 13, 13, NULL, '《迷糊餐厅》第三季继续讲述瓦古娜利亚家庭餐厅的日常故事。本季中，小鸟游宗太与种岛白杨的关系进一步发展，其他员工如佐藤润、轰八千代等也继续上演各种搞笑互动。餐厅迎来了新员工，带来了更多欢乐与混乱。故事围绕餐厅员工们的工作、生活与情感展开，充满温馨与幽默。', '[\"喜剧\",\"日常\",\"职场\",\"恋爱\"]', '《迷糊餐厅》第三季继续讲述瓦古娜利亚餐厅员工们的日常趣事，包括小鸟游宗太、种岛白杨、伊波真昼等角色在工作和生活中的搞笑互动。', NULL, '2026-02-09', '2015-07-04', '[\"福山潤\",\"小野大輔\",\"神谷浩史\",\"阿澄佳奈\",\"藤田咲\",\"喜多村英梨\",\"渡辺久美子\",\"広橋涼\",\"中田譲治\",\"川瀬晶子\"]', '[\"福山潤\",\"小野大輔\",\"神谷浩史\",\"阿澄佳奈\",\"藤田咲\",\"喜多村英梨\",\"渡辺久美子\",\"広橋涼\",\"中田譲治\",\"川瀬晶子\",\"福山润\",\"小野大辅\",\"渡边久美子\",\"广桥凉\",\"中田让治\",\"川濑晶子\"]', 1, '2026-02-09 23:24:47', '2026-03-18 17:58:17');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (73, '南家三姐妹 再来一碗', NULL, 'http://lain.bgm.tv/pic/cover/l/02/4d/890_dbMzz.jpg', 'completed', NULL, 13, 13, NULL, '《南家三姐妹 再来一碗》是《南家三姐妹》系列的第二季动画，继续讲述南家三姐妹——春香、夏奈和千秋的日常生活。本季中，三姐妹与同学们的关系更加深入，出现了更多有趣的互动和搞笑情节。从学校的日常到家庭的琐事，故事以轻松幽默的方式展现了少女们的成长与友情，充满了温馨与欢笑。', '[\"校园\",\"日常\",\"喜剧\",\"家庭\"]', '南家三姐妹的日常生活继续，春香、夏奈和千秋三姐妹与朋友们在学校和家中发生各种有趣的故事，展现了温馨的家庭生活和青春校园喜剧。', NULL, NULL, '2008-01-06', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"森永理科\",\"柿原徹也\",\"浅沼晋太郎\",\"喜多村英梨\",\"豊崎愛生\",\"後藤沙緒里\"]', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"森永理科\",\"柿原徹也\",\"浅沼晋太郎\",\"喜多村英梨\",\"豊崎愛生\",\"後藤沙緒里\",\"茅原实里\",\"水树奈奈\",\"柿原彻也\",\"丰崎爱生\",\"后藤沙绪里\"]', 1, '2026-02-09 23:25:05', '2026-03-18 17:58:25');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (74, '南家三姐妹 欢迎回来', NULL, 'http://lain.bgm.tv/pic/cover/l/07/87/889_qF2Qq.jpg', 'completed', NULL, 13, 13, NULL, '《南家三姐妹 欢迎回来》是《南家三姐妹》系列的第四季动画，继续讲述南家三姐妹春香、夏奈和千秋的日常生活。本季中，三姐妹与朋友们在学校和家中发生各种轻松有趣的日常故事，展现了她们之间深厚的姐妹情谊和青春期的点滴成长。动画延续了系列一贯的温馨搞笑风格，通过细腻的日常描写，让观众感受到平凡生活中的温暖与欢乐。', '[\"校园\",\"日常\",\"喜剧\",\"姐妹\"]', '南家三姐妹的日常生活继续，春香、夏奈和千秋三姐妹与朋友们一起度过温馨有趣的时光，展现了家庭亲情和青春成长的点点滴滴。', NULL, NULL, '2009-01-04', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"柿原徹也\",\"浅沼晋太郎\",\"喜多村英梨\",\"森永理科\",\"豊崎愛生\",\"後藤沙緒里\"]', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"柿原徹也\",\"浅沼晋太郎\",\"喜多村英梨\",\"森永理科\",\"豊崎愛生\",\"後藤沙緒里\",\"茅原实里\",\"水树奈奈\",\"柿原彻也\",\"丰崎爱生\",\"后藤沙绪里\"]', 1, '2026-02-09 23:25:14', '2026-03-18 18:03:33');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (75, '多田君不恋爱', NULL, 'http://lain.bgm.tv/pic/cover/l/05/f6/226734_Xgrmb.jpg', 'completed', '7.6', 13, 13, NULL, '故事围绕摄影社成员多田光良展开，他偶然帮助了迷路的德国留学生特蕾莎，并邀请她加入摄影社。随着日常校园生活的推进，光良与特蕾莎之间逐渐萌生微妙情感，但特蕾莎因身份问题面临回国抉择。作品细腻描绘了青春期的懵懂爱恋与成长烦恼，以清新画风和温馨日常打动观众。', '[\"校园\",\"恋爱\",\"日常\",\"青春\"]', '高中生多田光良在摄影社遇到奥地利留学生特蕾莎·瓦格纳，两人因摄影结缘，但多田坚持不恋爱，故事围绕他们的校园生活和情感发展展开。', NULL, NULL, '2018-04-05', '[\"田村睦心\",\"中村悠一\",\"石見舞菜香\",\"宮野真守\",\"三宅麻理恵\",\"下地紫野\",\"梅原裕一郎\",\"杉田智和\",\"石上静香\",\"下野紘\"]', '[\"田村睦心\",\"中村悠一\",\"石見舞菜香\",\"宮野真守\",\"三宅麻理恵\",\"下地紫野\",\"梅原裕一郎\",\"杉田智和\",\"石上静香\",\"下野紘\",\"石见舞菜香\",\"宫野真守\",\"三宅麻理惠\",\"下野纮\"]', 1, '2026-02-09 23:28:14', '2026-03-18 17:58:27');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (76, '关于前辈很烦人这件事', NULL, 'http://lain.bgm.tv/pic/cover/l/68/a5/309670_SCMw3.jpg', 'completed', NULL, 12, 12, NULL, '故事围绕职场新人五十岚双叶与前辈武田晴海展开。双叶觉得晴海前辈总是过度关心、爱管闲事，让她感到困扰。然而，在日复一日的相处中，双叶逐渐发现前辈笨拙的温柔与真诚，两人之间萌生出微妙的情感。作品以轻松幽默的笔触描绘职场中的温馨日常与青春恋爱物语。', '[\"职场\",\"恋爱\",\"日常\",\"喜剧\"]', '讲述职场新人女员工与烦人前辈之间的日常喜剧故事。', NULL, NULL, '2021-10-10', '[]', NULL, 1, '2026-02-09 23:28:25', '2026-03-18 17:58:30');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (77, '跟班×服务', NULL, 'http://lain.bgm.tv/pic/cover/l/b0/46/69944_FZmY2.jpg', 'completed', NULL, 13, 13, NULL, '改编自高津カリノ创作的四格漫画，讲述新人公务员山神露西在区役所工作期间与同事们发生的各种日常趣事。露西因名字过长常被同事取笑，但她乐观开朗的性格让她逐渐融入这个充满个性的公务员团队。作品以轻松幽默的方式展现了公务员职场生活，穿插着同事间的友情与微妙的情感发展。', '[\"职场\",\"喜剧\",\"日常\",\"公务员\"]', '故事围绕在北海道某市役所工作的公务员们展开，描绘了新人公务员山神露西与同事们在工作中的日常趣事和人际关系。', NULL, NULL, '2013-07-04', '[\"茅野愛衣\",\"鈴木達央\",\"中原麻衣\",\"櫻井孝宏\",\"豊崎愛生\",\"大久保瑠美\",\"小林ゆう\",\"高橋美佳子\",\"日高里菜\",\"小山力也\"]', '[\"茅野愛衣\",\"鈴木達央\",\"中原麻衣\",\"櫻井孝宏\",\"豊崎愛生\",\"大久保瑠美\",\"小林ゆう\",\"高橋美佳子\",\"日高里菜\",\"小山力也\",\"茅野爱衣\",\"铃木达央\",\"樱井孝宏\",\"丰崎爱生\",\"小林优\",\"高桥美佳子\"]', 1, '2026-02-09 23:28:34', '2026-03-18 17:58:33');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (78, '我们大家的河合庄', NULL, 'http://lain.bgm.tv/pic/cover/l/0b/80/89216_ZQFLX.jpg', 'completed', '5.7', 12, 12, NULL, '高中生宇佐和成因为父母工作调动，独自搬进了河合庄公寓。这里住着性格各异的房客：爱捉弄人的文学少女河合律、天然呆的城崎、腹黑的前辈住子，以及神秘的房东。在充满欢笑与温馨的日常中，宇佐逐渐融入这个特别的“大家庭”，并与河合律之间萌生了青涩的感情。作品以细腻的笔触描绘青春期的友情、爱情与成长。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"治愈\"]', '高中生宇佐和成搬进河合庄公寓，与几位性格各异的邻居共同生活，逐渐融入这个温馨小社区的故事。', NULL, NULL, '2014-04-03', '[\"井口祐一\",\"花澤香菜\",\"四宮豪\",\"佐藤利奈\",\"金元寿子\",\"小林沙苗\",\"薮内満里奈\",\"長南翔太\",\"竹下礼奈\",\"鳥部万里子\"]', '[\"井口祐一\",\"花澤香菜\",\"四宮豪\",\"佐藤利奈\",\"金元寿子\",\"小林沙苗\",\"薮内満里奈\",\"長南翔太\",\"竹下礼奈\",\"鳥部万里子\",\"花泽香菜\",\"四宫豪\",\"薮内满里奈\",\"长南翔太\",\"鸟部万里子\"]', 1, '2026-02-09 23:28:42', '2026-03-18 17:58:37');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (79, '中二病也要谈恋爱！', NULL, 'http://lain.bgm.tv/pic/cover/l/3d/fd/29648_hkoQV.jpg', 'completed', '7.7', 12, 12, NULL, '高中新生富樫勇太曾是一名重度中二病患者，初中毕业后决心隐藏过去，过上普通高中生活。然而，他遇到了自称“邪王真眼使者”的同班同学小鸟游六花。六花看穿了勇太的中二病历史，并强行与他缔结“契约”，两人的日常就此展开。作品以幽默温馨的方式描绘了青春期的幻想与现实交织的恋爱喜剧。', '[\"校园\",\"恋爱\",\"喜剧\",\"日常\",\"轻小说改编\"]', '高中男生富樫勇太曾患有中二病，自称“漆黑烈焰使”，升入高中后决心隐藏过去。然而，他遇到了自称“邪王真眼”的中二病少女小鸟游六花，两人之间展开了一段充满幻想与现实的青春恋爱喜剧。', NULL, NULL, '2012-10-03', '[\"福山潤\",\"内田真礼\",\"赤﨑千夏\",\"浅倉杏美\",\"上坂すみれ\",\"沖佳苗\",\"天野由梨\",\"福原香織\",\"設楽麻美\",\"保志総一朗\"]', '[\"福山潤\",\"内田真礼\",\"赤﨑千夏\",\"浅倉杏美\",\"上坂すみれ\",\"沖佳苗\",\"天野由梨\",\"福原香織\",\"設楽麻美\",\"保志総一朗\",\"福山润\",\"赤崎千夏\",\"浅仓杏美\",\"上坂堇\",\"冲佳苗\",\"福原香织\",\"设乐麻美\",\"保志总一朗\"]', 1, '2026-02-09 23:28:59', '2026-03-18 17:58:42');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (80, '中二病也要谈恋爱！恋', NULL, 'http://lain.bgm.tv/pic/cover/l/c8/e4/72942_VniXv.jpg', 'completed', '7.7', 12, 12, NULL, '《中二病也要谈恋爱！恋》是《中二病也要谈恋爱！》的第二季动画。故事延续前作，讲述高中二年级的富樫勇太与小鸟游六花继续他们的恋爱日常。六花虽然逐渐摆脱中二病，但两人关系面临新的挑战，包括新角色七宫智音的出现带来的情感波动。本季深入探讨青春期的成长、人际关系以及如何平衡幻想与现实，描绘了一段既甜蜜又充满波折的校园恋爱故事。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"轻小说改编\"]', '富樫勇太和小鸟游六花升入高中后，他们的中二病恋爱故事继续展开。随着新角色的加入和旧友重逢，他们的关系面临新的挑战和成长。', NULL, NULL, '2014-01-08', '[\"福山潤\",\"内田真礼\",\"赤﨑千夏\",\"浅倉杏美\",\"上坂すみれ\",\"長妻樹里\",\"沖佳苗\",\"山岡ゆり\",\"天野由梨\",\"福原香織\"]', '[\"福山潤\",\"内田真礼\",\"赤﨑千夏\",\"浅倉杏美\",\"上坂すみれ\",\"長妻樹里\",\"沖佳苗\",\"山岡ゆり\",\"天野由梨\",\"福原香織\",\"福山润\",\"赤崎千夏\",\"浅仓杏美\",\"上坂堇\",\"长妻树里\",\"冲佳苗\",\"山冈百合\",\"福原香织\"]', 1, '2026-02-09 23:29:08', '2026-03-18 17:58:45');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (81, 'Anne Happy♪', NULL, 'http://lain.bgm.tv/pic/cover/l/e4/51/138053_V3iiZ.jpg', 'completed', '7.0', 12, 12, NULL, '故事围绕一群被选入“幸福班”的学生展开，她们各自拥有不幸的体质，如总是遭遇意外、被动物讨厌等。在班主任的引导下，她们通过日常的校园生活与特殊课程，学习如何寻找幸福与快乐，逐渐建立起深厚的友谊，并共同面对生活中的各种挑战。', '[\"校园\",\"日常\",\"喜剧\",\"治愈\"]', '讲述一群被分配到“幸福班”的倒霉少女们，在老师的指导下努力寻找幸福的故事。', NULL, NULL, '2016-04-07', '[\"花守ゆみり\",\"白石晴香\",\"安野希世乃\",\"山村響\",\"吉岡茉祐\",\"原由実\",\"森永千才\",\"小清水亜美\",\"儀武ゆう子\",\"鷄冠井美智子\"]', '[\"花守ゆみり\",\"白石晴香\",\"安野希世乃\",\"山村響\",\"吉岡茉祐\",\"原由実\",\"森永千才\",\"小清水亜美\",\"儀武ゆう子\",\"鷄冠井美智子\",\"花守由美里\",\"山村响\",\"吉冈茉祐\",\"原由实\",\"小清水亚美\",\"仪武祐子\",\"鸡冠井美智子\"]', 1, '2026-02-09 23:29:16', '2026-03-18 17:58:49');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (82, '古见同学有交流障碍症', NULL, 'http://lain.bgm.tv/pic/cover/l/e4/44/335225_UmKwl.jpg', 'completed', '7.8', 12, 12, NULL, '古见硝子是一位容貌出众、成绩优异的高中生，但她患有严重的交流障碍症，无法正常与人对话。转学第一天，她遇到了唯一能理解她的同学只野仁人。只野发现古见渴望交朋友，于是决定帮助她实现“交100个朋友”的目标。故事围绕两人在校园中的日常展开，描绘古见逐渐克服障碍、与他人建立联系的温馨过程。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"治愈\"]', '古见硝子是一位外表完美但患有严重交流障碍症的高中女生，她渴望交朋友却无法正常与人沟通。在同学只野仁人的帮助下，她开始努力克服障碍，目标是交到100个朋友。', NULL, NULL, '2021-10-06', '[\"古賀葵\",\"梶原岳人\",\"村川梨衣\",\"前島亜美\",\"藤井ゆきよ\",\"日高里菜\",\"大久保瑠美\",\"潘めぐみ\",\"青木瑠璃子\",\"森山由梨佳\"]', '[\"古賀葵\",\"梶原岳人\",\"村川梨衣\",\"前島亜美\",\"藤井ゆきよ\",\"日高里菜\",\"大久保瑠美\",\"潘めぐみ\",\"青木瑠璃子\",\"森山由梨佳\",\"古贺葵\",\"前岛亚美\",\"藤井由纪代\",\"潘惠美\",\"青木琉璃子\",\"藤井幸代\"]', 1, '2026-02-09 23:29:24', '2026-03-18 17:58:52');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (83, '向山进发 第一季', NULL, 'http://lain.bgm.tv/pic/cover/l/bf/3b/86670_Ze8H4.jpg', 'completed', NULL, 12, 12, NULL, '《向山进发》是一部以登山为主题的日常动画，讲述了高中生仓上日向在好友雪村葵的引导下，开始接触登山运动的故事。日向原本是个室内派，但在葵的鼓励下逐渐发现了登山的乐趣。两人一起挑战各种山峰，在登山过程中不仅锻炼了身体，也加深了彼此的友谊，体验到了大自然的壮丽与美好。', '[\"日常\",\"运动\",\"治愈\",\"友情\"]', '故事讲述患有恐高症的女高中生葵，在好友日向的鼓励下开始尝试登山，两人一起探索附近的山峰，逐渐克服恐惧并享受登山乐趣的日常故事。', NULL, NULL, '2018-07-02', '[\"井口裕香\",\"阿澄佳奈\",\"日笠陽子\",\"小倉唯\",\"久川綾\",\"牧野由依\",\"荻野晴朗\",\"儀武ゆう子\",\"東山奈央\",\"伊丸岡篤\"]', '[\"井口裕香\",\"阿澄佳奈\",\"日笠陽子\",\"小倉唯\",\"久川綾\",\"牧野由依\",\"荻野晴朗\",\"儀武ゆう子\",\"東山奈央\",\"伊丸岡篤\",\"日笠阳子\",\"小仓唯\",\"久川绫\",\"仪武祐子\",\"东山奈央\",\"伊丸冈笃\"]', 1, '2026-02-09 23:29:40', '2026-03-18 17:58:55');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (84, '向山进发 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/bf/3b/86670_Ze8H4.jpg', 'completed', '7.4', 24, 24, NULL, '本季延续第一季的故事，讲述热爱登山的高中女生雪村葵与青梅竹马仓上日向继续她们的登山冒险。在第二季中，两人不仅挑战了更多日本名山，还结识了新的登山伙伴，共同克服困难、欣赏自然美景。通过登山活动，她们加深了友谊，也各自获得了成长与感悟。', '[\"日常\",\"治愈\",\"运动\",\"校园\"]', '高中女生们继续她们的登山冒险，探索更多山峰，加深友谊，面对新的挑战。', NULL, NULL, '2014-07-09', '[\"井口裕香\",\"阿澄佳奈\",\"日笠陽子\",\"小倉唯\",\"久川綾\",\"牧野由依\",\"山下誠一郎\",\"荻野晴朗\",\"儀武ゆう子\",\"小松史法\"]', '[\"井口裕香\",\"阿澄佳奈\",\"日笠陽子\",\"小倉唯\",\"久川綾\",\"牧野由依\",\"山下誠一郎\",\"荻野晴朗\",\"儀武ゆう子\",\"小松史法\",\"日笠阳子\",\"小仓唯\",\"久川绫\",\"山下诚一郎\",\"仪武优子\"]', 1, '2026-02-09 23:29:48', '2026-03-18 17:58:58');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (85, '向山进发 第三季', NULL, 'http://lain.bgm.tv/pic/cover/l/49/a2/216310_ci5yT.jpg', 'completed', NULL, 13, 13, NULL, '《向山进发》第三季继续讲述热爱登山的高中女生雪村葵和日向的登山故事。本季中，两人不仅挑战了更高难度的山峰，还遇到了新的登山伙伴，共同探索更多美丽的自然景观。通过登山活动，她们不仅锻炼了身体，更深化了彼此的友谊，学会了面对困难时的坚持与勇气。', '[\"日常\",\"治愈\",\"运动\",\"校园\"]', '《向山进发》第三季继续讲述热爱登山的少女们的故事。本季中，主角们将挑战更高难度的山峰，在登山过程中加深友谊，克服困难，享受大自然的壮丽景色。', NULL, NULL, '2018-07-02', '[\"井口裕香\",\"阿澄佳奈\",\"日笠陽子\",\"小倉唯\",\"久川綾\",\"牧野由依\",\"荻野晴朗\",\"儀武ゆう子\",\"東山奈央\",\"伊丸岡篤\"]', '[\"井口裕香\",\"阿澄佳奈\",\"日笠陽子\",\"小倉唯\",\"久川綾\",\"牧野由依\",\"荻野晴朗\",\"儀武ゆう子\",\"東山奈央\",\"伊丸岡篤\",\"日笠阳子\",\"小仓唯\",\"久川绫\",\"仪武祐子\",\"东山奈央\"]', 1, '2026-02-09 23:29:56', '2026-03-18 17:59:00');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (89, '向山进发 第四季', NULL, 'http://lain.bgm.tv/pic/cover/l/ad/4c/1938_B18cB.jpg', 'completed', NULL, 12, 12, NULL, '本季继续讲述热爱登山的女高中生雪村葵与朋友们一起挑战更高山峰的故事。随着登山经验的积累，她们开始尝试更专业的装备和技术，面对更复杂的山路和天气挑战。在攀登过程中，葵与好友日向的友情不断加深，同时也结识了更多志同道合的登山伙伴。作品通过细腻的日常描写，展现了登山运动的魅力与团队合作的重要性。', '[\"日常\",\"运动\",\"治愈\",\"校园\",\"友情\"]', '《向山进发》第四季继续讲述热爱登山的少女们的故事。本季中，主角们将挑战更高难度的山峰，在登山过程中面对新的挑战和成长，同时加深彼此之间的友谊。', NULL, NULL, '2022-01-23', '[]', NULL, 1, '2026-02-09 23:35:52', '2026-03-18 17:59:04');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (90, '宇崎学妹想要玩 第一季', NULL, 'http://lain.bgm.tv/pic/cover/l/5a/42/299498_PNyTT.jpg', 'completed', NULL, 12, 12, NULL, '大学生樱井真一性格孤僻，喜欢独处。然而，高中时期的学妹宇崎花却总是缠着他一起玩。宇崎花活泼开朗，身材娇小却充满活力，她以各种理由接近樱井，两人之间展开了一段轻松有趣的校园日常。这部作品描绘了学长与学妹之间温馨又搞笑的互动，展现了青春校园生活的美好。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\"]', '大学生樱井真一在打工时遇到了高中时期的学妹宇崎花，这位活泼开朗的学妹总是缠着他一起玩耍，让他的日常生活变得热闹非凡。', NULL, NULL, '2022-10-01', '[\"大空直美\",\"赤羽根健治\",\"竹達彩奈\",\"髙木朋弥\",\"秋元羊介\",\"早見沙織\",\"加藤聖奈\",\"石川英郎\",\"三瓶由布子\",\"伊藤美紀\"]', '[\"大空直美\",\"赤羽根健治\",\"竹達彩奈\",\"髙木朋弥\",\"秋元羊介\",\"早見沙織\",\"加藤聖奈\",\"石川英郎\",\"三瓶由布子\",\"伊藤美紀\",\"竹达彩奈\",\"高木朋弥\",\"早见沙织\",\"加藤圣奈\",\"伊藤美纪\"]', 1, '2026-02-09 23:36:02', '2026-03-18 17:59:06');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (91, '宇崎学妹想要玩 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/70/d8/315744_GMmR6.jpg', 'completed', '7.4', 12, 12, NULL, '宇崎花是樱井真一的高中学妹，性格活泼开朗，总是缠着这位性格孤僻的学长一起玩耍。第二季延续了两人温馨有趣的日常互动，宇崎花继续用她充满活力的方式“照顾”着学长，而樱井真一虽然表面冷淡，内心却逐渐被学妹的热情所融化。故事展现了青春校园中轻松愉快的相处时光，以及两人之间微妙的情感变化。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\"]', '宇崎学妹继续以她活泼开朗的性格缠着学长樱井真一玩耍，两人之间的日常互动充满欢笑与温馨，关系也逐渐变得更加亲密。', NULL, NULL, '2022-10-01', '[\"大空直美\",\"赤羽根健治\",\"竹達彩奈\",\"髙木朋弥\",\"秋元羊介\",\"早見沙織\",\"加藤聖奈\",\"石川英郎\",\"三瓶由布子\",\"伊藤美紀\"]', '[\"大空直美\",\"赤羽根健治\",\"竹達彩奈\",\"髙木朋弥\",\"秋元羊介\",\"早見沙織\",\"加藤聖奈\",\"石川英郎\",\"三瓶由布子\",\"伊藤美紀\",\"竹达彩奈\",\"高木朋弥\",\"早见沙织\",\"加藤圣奈\",\"伊藤美纪\"]', 1, '2026-02-09 23:36:10', '2026-03-18 17:59:10');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (92, '辉夜大小姐想让我告白 第一季', NULL, 'http://lain.bgm.tv/pic/cover/l/2a/f7/248175_2w4zT.jpg', 'completed', '7.0', 12, 12, NULL, '秀知院学园是精英云集的贵族学校，学生会副会长四宫辉夜与会长白银御行互相暗恋，但两人都自尊心极强，认为先告白的一方会在恋爱中处于劣势。于是他们展开了一场精妙的心理攻防战，运用各种策略试图让对方先告白，上演了一出充满智慧与幽默的恋爱头脑战。', '[\"校园\",\"恋爱\",\"喜剧\",\"日常\"]', '秀知院学园的学生会副会长四宫辉夜与会长白银御行互相暗恋，但两人都因自尊心过强而不愿先告白，展开了一场充满策略与心理战的恋爱头脑战。', NULL, NULL, '2022-04-08', '[\"古賀葵\",\"古川慎\",\"小原好美\",\"鈴木崚汰\",\"富田美憂\",\"花守ゆみり\",\"麻倉もも\",\"日高里菜\",\"八代拓\",\"市ノ瀬加那\"]', '[\"古賀葵\",\"古川慎\",\"小原好美\",\"鈴木崚汰\",\"富田美憂\",\"花守ゆみり\",\"麻倉もも\",\"日高里菜\",\"八代拓\",\"市ノ瀬加那\",\"古贺葵\",\"铃木崚汰\",\"富田美忧\",\"花守由美里\",\"麻仓桃\",\"市之濑加那\"]', 1, '2026-02-09 23:36:20', '2026-03-18 17:59:13');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (93, '辉夜大小姐想让我告白 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/36/16/293049_0e0re.jpg', 'completed', '7.0', 12, 12, NULL, '秀知院学园学生会副会长四宫辉夜与会长白银御行互相暗恋，却因自尊心作祟，都不愿先告白，而是想方设法让对方先开口。第二季中，两人继续展开高智商的恋爱头脑战，同时学生会成员藤原千花、石上优等人的故事也更加丰富，展现了青春校园中微妙又甜蜜的情感博弈。', '[\"校园\",\"恋爱\",\"喜剧\",\"日常\"]', '秀知院学园的学生会副会长四宫辉夜与会长白银御行互相喜欢，但两人都因自尊心过强而不愿先告白，展开了一场充满策略与心理战的恋爱头脑战。', NULL, NULL, '2022-04-08', '[\"古賀葵\",\"古川慎\",\"小原好美\",\"鈴木崚汰\",\"富田美憂\",\"花守ゆみり\",\"麻倉もも\",\"日高里菜\",\"八代拓\",\"市ノ瀬加那\"]', '[\"古賀葵\",\"古川慎\",\"小原好美\",\"鈴木崚汰\",\"富田美憂\",\"花守ゆみり\",\"麻倉もも\",\"日高里菜\",\"八代拓\",\"市ノ瀬加那\",\"古贺葵\",\"铃木崚汰\",\"富田美忧\",\"花守由美里\",\"麻仓桃\",\"市之濑加那\"]', 1, '2026-02-09 23:36:29', '2026-03-18 17:59:17');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (94, '辉夜大小姐想让我告白 第三季', NULL, 'http://lain.bgm.tv/pic/cover/l/cf/9c/317613_bpGX4.jpg', 'completed', '7.0', 13, 13, NULL, '秀知院学园学生会会长白银御行与副会长四宫辉夜，两位天才在互相暗恋却都不愿先告白的心理战中继续斗智斗勇。第三季中，两人关系迎来重大进展，文化祭筹备、圣诞派对等事件让他们的感情面临新的考验与突破，浪漫氛围达到系列巅峰。', '[\"校园\",\"恋爱\",\"喜剧\",\"日常\"]', '学生会会长白银御行与副会长四宫辉夜互相暗恋，但两人都因自尊心过强而无法主动告白，反而想方设法让对方先表白。第三季中，他们的关系在各种校园活动和日常互动中进一步发展，同时学生会成员们的故事也更加丰富。', NULL, NULL, '2022-04-08', '[\"古賀葵\",\"古川慎\",\"小原好美\",\"鈴木崚汰\",\"富田美憂\",\"花守ゆみり\",\"麻倉もも\",\"日高里菜\",\"八代拓\",\"市ノ瀬加那\"]', '[\"古賀葵\",\"古川慎\",\"小原好美\",\"鈴木崚汰\",\"富田美憂\",\"花守ゆみり\",\"麻倉もも\",\"日高里菜\",\"八代拓\",\"市ノ瀬加那\",\"古贺葵\",\"铃木崚汰\",\"富田美忧\",\"花守由美里\",\"麻仓桃\",\"市之濑加那\"]', 1, '2026-02-09 23:36:38', '2026-03-18 17:59:20');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (95, '牵牛花与加濑同学', NULL, 'http://lain.bgm.tv/pic/cover/l/22/86/223818_II9yT.jpg', 'completed', NULL, 1, 1, NULL, '山田结衣是班上的园艺委员，性格内向害羞。加濑同学是田径部的王牌，外表帅气、成绩优秀，是学校里的风云人物。两人因牵牛花而相识，内向的结衣渐渐被开朗的加濑吸引，而加濑也对温柔的结衣产生好感。影片细腻描绘了两位高中女生之间从相识、相知到相恋的纯真情感，以及她们在青春岁月中共同成长的故事。', '[\"校园\",\"恋爱\",\"日常\",\"百合\",\"青春\"]', '高中女生山田结衣与田径部明星加濑友香之间的青春恋爱故事，描绘了两人从相识到相恋的温馨日常。', NULL, NULL, '2018-11-21', '[\"髙橋ミナミ\",\"佐倉綾音\",\"木戸衣吹\"]', '[\"髙橋ミナミ\",\"佐倉綾音\",\"木戸衣吹\",\"高桥美波\",\"高桥美奈美\",\"佐仓绫音\",\"木户衣吹\"]', 1, '2026-02-09 23:36:46', '2026-03-18 17:59:22');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (96, '摇曳露营△ 第一季', NULL, 'http://lain.bgm.tv/pic/cover/l/18/bc/207195_2Cp3o.jpg', 'completed', NULL, 12, 12, NULL, '独自露营的高中女生志摩凛在富士山附近偶遇了因迷路而陷入困境的露营新手各务原抚子。这次相遇让抚子对露营产生了浓厚兴趣，并加入了学校的野外活动社团。故事围绕凛、抚子以及社团成员们一起享受露营乐趣的温馨日常展开，描绘了她们在不同季节、不同露营地的美好时光。', '[\"日常\",\"治愈\",\"露营\",\"校园\",\"旅行\"]', '独自露营的高中女生志摩凛在富士山附近偶遇了正在露营的抚子，两人由此展开了一段围绕露营的温馨日常故事。', NULL, NULL, '2021-01-07', '[\"花守ゆみり\",\"東山奈央\",\"原紗友里\",\"豊崎愛生\",\"高橋李依\",\"伊藤静\",\"松田利冴\",\"黒沢ともよ\",\"井上麻里奈\",\"山本希望\"]', '[\"花守ゆみり\",\"東山奈央\",\"原紗友里\",\"豊崎愛生\",\"高橋李依\",\"伊藤静\",\"松田利冴\",\"黒沢ともよ\",\"井上麻里奈\",\"山本希望\",\"花守由美里\",\"东山奈央\",\"原纱友里\",\"丰崎爱生\",\"高桥李依\",\"黑泽朋世\"]', 1, '2026-02-09 23:36:55', '2026-03-18 17:59:26');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (97, '摇曳露营△ 第二季', '摇曳露营△ 第二季', 'https://lain.bgm.tv/pic/cover/l/0f/50/262897_d3555.jpg', 'completed', '7.4', 13, 13, NULL, '本季继续讲述志摩凛、各务原抚子等热爱露营的少女们的温馨日常。随着抚子加入野外活动社团，她们开始探索更多露营地点，从富士山脚下的本栖湖到冬季的志摩原高原。故事不仅展现了露营的乐趣与自然美景，还深入描绘了角色间的友情成长与各自对未来的思考，延续了治愈系户外生活的主题。', '[\"日常\",\"治愈\",\"户外\",\"友情\",\"美食\"]', '《摇曳露营△》第二季继续讲述几位热爱露营的女高中生的温馨日常。她们在富士山周边露营，分享美食，享受大自然，同时加深彼此之间的友谊。', NULL, '2026-02-09', '2021-01-07', '[\"花守ゆみり\",\"東山奈央\",\"原紗友里\",\"豊崎愛生\",\"高橋李依\",\"伊藤静\",\"松田利冴\",\"黒沢ともよ\",\"井上麻里奈\",\"山本希望\"]', '[\"花守ゆみり\",\"東山奈央\",\"原紗友里\",\"豊崎愛生\",\"高橋李依\",\"伊藤静\",\"松田利冴\",\"黒沢ともよ\",\"井上麻里奈\",\"山本希望\",\"花守由美里\",\"东山奈央\",\"原纱友里\",\"丰崎爱生\",\"高桥李依\",\"黑泽朋世\"]', 1, '2026-02-09 23:37:05', '2026-03-18 17:59:28');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (98, '漫画女孩', NULL, 'http://lain.bgm.tv/pic/cover/l/27/97/217249_jIbkA.jpg', 'completed', '4.7', 12, 12, NULL, '故事围绕15岁的少女漫画家萌田薰子展开，她为了追求漫画梦想而入住女子漫画家宿舍。薰子虽然画技稚嫩且缺乏自信，但在室友们的鼓励和帮助下，逐渐克服创作瓶颈，与同样怀揣梦想的少女漫画家们共同成长，描绘出充满欢笑与泪水的青春物语。', '[\"校园\",\"日常\",\"喜剧\",\"百合\",\"励志\"]', '一位热爱漫画的高中女生与朋友们一起创作同人志的故事，描绘了她们在创作过程中的欢笑、挑战和成长。', NULL, NULL, '2018-04-05', '[\"赤尾ひかる\",\"本渡楓\",\"大西沙織\",\"高橋李依\",\"遠藤綾\",\"津田美波\",\"七瀬彩夏\",\"上田麗奈\",\"能登麻美子\",\"川澄綾子\"]', '[\"赤尾ひかる\",\"本渡楓\",\"大西沙織\",\"高橋李依\",\"遠藤綾\",\"津田美波\",\"七瀬彩夏\",\"上田麗奈\",\"能登麻美子\",\"川澄綾子\",\"赤尾光\",\"本渡枫\",\"大西沙织\",\"高桥李依\",\"远藤绫\",\"七濑彩夏\",\"上田丽奈\",\"川澄绫子\"]', 1, '2026-02-09 23:37:13', '2026-03-18 17:59:31');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (99, '白圣女与黑牧师', NULL, 'http://lain.bgm.tv/pic/cover/l/0f/0b/387822_nHUhn.jpg', 'completed', NULL, 12, 12, NULL, '讲述住在教会里的圣女塞西莉亚与牧师劳伦斯之间的温馨日常故事。塞西莉亚外表圣洁但性格天然呆，劳伦斯看似严肃实则温柔体贴，两人在平静的教会生活中逐渐加深感情，展开一段充满治愈与甜蜜的恋爱喜剧。', '[\"恋爱\",\"日常\",\"治愈\",\"喜剧\"]', '讲述圣女塞西莉亚与牧师劳伦斯之间温馨治愈的日常故事，两人性格迥异却相互扶持，在教会生活中发生各种有趣互动。', NULL, NULL, '2023-07-12', '[\"澤田姫\",\"島袋美由利\",\"石川界人\",\"石谷春貴\",\"中村カンナ\",\"戸松遥\",\"中原麻衣\",\"小市眞琴\",\"前野智昭\",\"上田麗奈\"]', '[\"澤田姫\",\"島袋美由利\",\"石川界人\",\"石谷春貴\",\"中村カンナ\",\"戸松遥\",\"中原麻衣\",\"小市眞琴\",\"前野智昭\",\"上田麗奈\",\"泽田姬\",\"岛袋美由利\",\"石谷春贵\",\"中村加奈\",\"户松遥\",\"小市真琴\",\"上田丽奈\"]', 1, '2026-02-09 23:37:22', '2026-03-18 17:59:34');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (100, '未确认进行式', NULL, 'http://lain.bgm.tv/pic/cover/l/4a/80/83869_vIW6y.jpg', 'completed', '6.9', 12, 12, NULL, '普通女高中生夜之森小红某天突然被告知有未婚夫，对方竟是自称“未确认生物”的白夜。随着白夜和其妹妹三峰真白搬进家中，小红开始了与这对神秘兄妹的同居生活。在充满欢笑与温馨的日常中，小红逐渐了解白夜的秘密，并与他建立起特殊的情感纽带。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"奇幻\"]', '普通女高中生夜之森小红突然被告知与未婚夫白夜和妹妹白夜一起生活，三人开始了充满意外与欢乐的同居日常。', NULL, NULL, '2014-01-08', '[\"照井春佳\",\"松井恵理子\",\"吉田有里\",\"羽多野渉\",\"愛美\",\"佐倉綾音\",\"藤田咲\",\"角元明日香\",\"渡部優衣\",\"駒形友梨\"]', '[\"照井春佳\",\"松井恵理子\",\"吉田有里\",\"羽多野渉\",\"愛美\",\"佐倉綾音\",\"藤田咲\",\"角元明日香\",\"渡部優衣\",\"駒形友梨\",\"松井惠理子\",\"羽多野涉\",\"爱美\",\"佐仓绫音\",\"渡部优衣\",\"驹形友梨\"]', 1, '2026-02-09 23:37:29', '2026-03-18 17:59:36');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (101, '相合之物', NULL, 'http://lain.bgm.tv/pic/cover/l/41/49/333664_d4Py9.jpg', 'completed', '6.7', 12, 12, NULL, '故事讲述在京都老字号和果子店「绿松」长大的纳野和，曾梦想成为音乐人而前往东京，但事业不顺后回到老家。他决定继承家业，与父亲收养的少女雪平一果相遇。一果为了寻找生母而来到京都，两人在传统和果子店中共同生活，通过制作和果子逐渐建立起家人般的羁绊，温暖治愈的日常故事就此展开。', '[\"日常\",\"治愈\",\"美食\",\"家庭\"]', '讲述一位年轻男子回到家乡京都，继承家族传统和菓子店，在与家人和顾客的互动中重新发现生活意义的故事。', NULL, NULL, '2022-04-06', '[\"渡辺はるか\",\"島﨑信長\",\"結木梢\",\"小山力也\",\"大原さやか\",\"岩崎ひろし\",\"ゆきのさつき\",\"永塚拓馬\",\"鈴木みのり\",\"髙橋ミナミ\"]', '[\"渡辺はるか\",\"島﨑信長\",\"結木梢\",\"小山力也\",\"大原さやか\",\"岩崎ひろし\",\"ゆきのさつき\",\"永塚拓馬\",\"鈴木みのり\",\"髙橋ミナミ\",\"渡边遥\",\"岛崎信长\",\"结木梢\",\"大原沙耶香\",\"岩崎宏\",\"雪野五月\",\"永冢拓马\",\"铃木实里\",\"高桥美波\"]', 1, '2026-02-09 23:37:38', '2026-03-18 17:59:39');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (102, '明日酱的水手服', NULL, 'http://lain.bgm.tv/pic/cover/l/07/95/331480_c2aq9.jpg', 'completed', NULL, 12, 12, NULL, '故事讲述乡下女孩明日小路梦想穿上母亲母校的漂亮水手服，考入名门女子中学蜡梅学园。她以独特的开朗个性与同学们相遇，在充满个性的班级中，通过每日的校园生活，描绘少女们闪闪发光的青春故事。作品以细腻的笔触展现少女间的友情与成长，充满温暖治愈的氛围。', '[\"校园\",\"日常\",\"治愈\",\"少女\"]', '明日小路梦想成为母亲母校的偶像，考入蜡梅学园中学部，却发现自己竟是唯一穿水手服的学生。她决心用开朗个性感染周围，在校园生活中寻找属于自己的闪耀时刻。', NULL, NULL, '2022-01-08', '[\"村上まなつ\",\"雨宮天\",\"鬼頭明里\",\"若山詩音\",\"関根明良\",\"石上静香\",\"石川由依\",\"麻倉もも\",\"田所あずさ\",\"伊藤美来\"]', '[\"村上まなつ\",\"雨宮天\",\"鬼頭明里\",\"若山詩音\",\"関根明良\",\"石上静香\",\"石川由依\",\"麻倉もも\",\"田所あずさ\",\"伊藤美来\",\"村上真夏\",\"雨宫天\",\"鬼头明里\",\"若山诗音\",\"关根明良\",\"麻仓桃\",\"田所梓\"]', 1, '2026-02-09 23:37:46', '2026-03-18 17:59:42');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (103, '摇曳露营△ 第三季', '摇曳露营△ 第三季', 'https://lain.bgm.tv/pic/cover/l/19/1a/405785_u9it9.jpg', 'completed', NULL, 13, 13, NULL, '本季继续讲述各务原抚子、志摩凛等露营爱好者的温馨日常。随着抚子升入大学，故事舞台扩展至山梨县，她们将探索新的露营地点，结识更多热爱户外活动的伙伴，在美丽的自然风光中分享美食、交流心得，延续系列轻松治愈的风格。', '[\"日常\",\"治愈\",\"露营\",\"美食\",\"旅行\"]', '《摇曳露营△》第三季继续讲述几位热爱露营的女高中生的温馨日常，她们在富士山周边露营，分享美食与快乐，体验户外生活的乐趣。', NULL, '2026-02-09', '2024-04-04', '[\"花守ゆみり\",\"東山奈央\",\"原紗友里\",\"豊崎愛生\",\"高橋李依\",\"伊藤静\",\"黒沢ともよ\",\"指出毬亜\",\"天野心愛\",\"井上麻里奈\"]', '[\"花守ゆみり\",\"東山奈央\",\"原紗友里\",\"豊崎愛生\",\"高橋李依\",\"伊藤静\",\"黒沢ともよ\",\"指出毬亜\",\"天野心愛\",\"井上麻里奈\",\"花守由美里\",\"东山奈央\",\"原纱友里\",\"丰崎爱生\",\"高桥李依\",\"黑泽朋世\",\"指出球亚\",\"天野心爱\"]', 1, '2026-02-09 23:40:45', '2026-03-18 17:59:45');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (104, '摇曳百合 第一季', NULL, 'http://lain.bgm.tv/pic/cover/l/43/d9/14588_bDB2r.jpg', 'completed', NULL, 12, 12, NULL, '故事围绕七森中学的“娱乐部”展开，四位初中女生——赤座灯里、岁纳京子、船见结衣和吉川千夏——在几乎没有活动的社团里度过悠闲的校园时光。她们常常聚在一起喝茶、聊天、玩游戏，偶尔也会因为各种小事引发轻松有趣的日常闹剧。作品以轻松幽默的方式描绘了少女们之间温馨的友情与互动，充满了治愈系的氛围。', '[\"校园\",\"日常\",\"搞笑\",\"治愈\",\"百合\"]', '讲述四位初中女生在娱乐部度过的轻松日常喜剧故事，以百合元素和幽默互动为特色。', NULL, NULL, '2012-07-02', '[\"三上枝織\",\"大坪由佳\",\"津田美波\",\"大久保瑠美\",\"三森すずこ\",\"加藤英美里\",\"斎藤千和\",\"日高里菜\",\"藤田咲\",\"倉口桃\"]', '[\"三上枝織\",\"大坪由佳\",\"津田美波\",\"大久保瑠美\",\"三森すずこ\",\"加藤英美里\",\"斎藤千和\",\"日高里菜\",\"藤田咲\",\"倉口桃\",\"三上枝织\",\"三森铃子\",\"斋藤千和\",\"仓口桃\"]', 1, '2026-02-09 23:40:54', '2026-03-18 17:59:47');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (105, '雏子的笔记', NULL, 'http://lain.bgm.tv/pic/cover/l/b2/0c/190907_H0Lox.jpg', 'completed', '6.8', 12, 12, NULL, '不擅长与人交流的樱木雏子为了克服自己的社交恐惧症，决定加入高中演剧部。她来到东京寄宿在祖母经营的四季庄，与一群性格各异的房客们相遇。在追寻演剧梦想的过程中，雏子逐渐打开心扉，与朋友们共同成长，体验充满欢笑与感动的校园生活。', '[\"校园\",\"日常\",\"喜剧\",\"治愈\"]', '内向的少女雏子为了克服在人前紧张到变成稻草人的毛病，来到东京的春夏秋冬庄寄宿，与一群个性鲜明的女孩们共同生活，并努力实现成为演员的梦想。', NULL, NULL, '2017-04-07', '[\"栗本有規\",\"M・A・O\",\"小倉唯\",\"高野麻里佳\",\"遠藤璃菜\",\"東城日沙子\",\"内藤穂之香\",\"富田美憂\",\"吉田有里\",\"佐藤奏美\"]', '[\"栗本有規\",\"M・A・O\",\"小倉唯\",\"高野麻里佳\",\"遠藤璃菜\",\"東城日沙子\",\"内藤穂之香\",\"富田美憂\",\"吉田有里\",\"佐藤奏美\",\"栗本有规\",\"市道真央\",\"小仓唯\",\"远藤璃菜\",\"东城日沙子\",\"内藤穗之香\",\"富田美忧\"]', 1, '2026-02-09 23:41:02', '2026-03-18 17:59:49');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (106, 'Urara迷路帖', NULL, 'http://lain.bgm.tv/pic/cover/l/d8/88/173303_pSp45.jpg', 'completed', '7.1', 12, 12, NULL, '在充满神秘色彩的迷路镇，少女千矢为了寻找母亲而来到此地，并立志成为一流的占卜师“Urara”。她进入“枣屋”与其他三位少女一起学习占卜术，在修行中经历各种有趣事件，逐渐成长并加深彼此友谊的温馨日常故事。', '[\"日常\",\"治愈\",\"奇幻\",\"百合\",\"喜剧\"]', '在迷路町，少女们为了成为占卜师而努力学习，展开温馨有趣的日常故事。', NULL, NULL, '2017-01-05', '[\"原田彩楓\",\"本渡楓\",\"久保ユリカ\",\"佳村はるか\",\"茅野愛衣\",\"諏訪彩花\",\"高倉有加\",\"咲々木瞳\",\"能登麻美子\",\"矢作紗友里\"]', '[\"原田彩楓\",\"本渡楓\",\"久保ユリカ\",\"佳村はるか\",\"茅野愛衣\",\"諏訪彩花\",\"高倉有加\",\"咲々木瞳\",\"能登麻美子\",\"矢作紗友里\",\"原田彩枫\",\"本渡枫\",\"久保由利香\",\"佳村遥\",\"茅野爱衣\",\"诹访彩花\",\"高仓有加\",\"咲咲木瞳\",\"矢作纱友里\"]', 1, '2026-02-09 23:41:09', '2026-03-18 17:59:51');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (107, '黄金拼图', NULL, 'http://lain.bgm.tv/pic/cover/l/9b/42/57978_NK1n4.jpg', 'completed', '6.9', 12, 12, NULL, '故事围绕英国留学生大宫忍与日本高中生爱丽丝·卡塔雷特的相遇展开。忍曾在英国寄宿家庭生活，回国后与爱丽丝重逢，两人与同班同学小路绫、猪熊阳子、九条可怜一起度过愉快的校园生活。作品以轻松温馨的日常为主线，描绘了少女们之间的友谊与成长，充满了治愈与欢乐的氛围。', '[\"校园\",\"日常\",\"治愈\",\"百合\",\"喜剧\",\"搞笑\"]', '日本高中生大宫忍与英国留学生爱丽丝重逢，她们与朋友们一起度过充满欢笑与温馨的校园生活，探索友谊与文化交流的故事。', NULL, NULL, '2013-07-06', '[\"西明日香\",\"田中真奈美\",\"種田梨沙\",\"内山夕実\",\"東山奈央\",\"田村ゆかり\",\"高橋美佳子\",\"木村亜希子\",\"佐藤聡美\",\"諏訪彩花\"]', '[\"西明日香\",\"田中真奈美\",\"種田梨沙\",\"内山夕実\",\"東山奈央\",\"田村ゆかり\",\"高橋美佳子\",\"木村亜希子\",\"佐藤聡美\",\"諏訪彩花\",\"种田梨沙\",\"内山夕实\",\"东山奈央\",\"田村由香里\",\"高桥美佳子\",\"木村亚希子\",\"佐藤聪美\",\"诹访彩花\"]', 1, '2026-02-09 23:41:18', '2026-03-18 17:59:54');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (108, '满溢的水果挞', NULL, 'http://lain.bgm.tv/pic/cover/l/0d/2e/279059_NNOnk.jpg', 'completed', NULL, 12, 12, NULL, '故事讲述梦想成为偶像的樱衣乃搬到东京，却意外加入了濒临解散的偶像组合“水果挞”。成员们性格各异，实力参差不齐，她们一边在秋叶原的咖啡店打工，一边努力进行偶像活动。作品以轻松幽默的方式描绘了这群少女在追逐梦想过程中的成长与羁绊，展现了偶像行业的酸甜苦辣。', '[\"偶像\",\"日常\",\"喜剧\",\"音乐\",\"萌系\"]', '五位少女组成偶像团体“水果挞”，在东京合租公寓中追求梦想的日常喜剧故事。', NULL, NULL, '2020-10-12', '[\"新田ひより\",\"保科李沙\",\"白石晴香\",\"近藤玲奈\",\"守屋亨香\",\"日笠陽子\",\"巽悠衣子\",\"佐倉薫\",\"篠原侑\",\"田中貴子\"]', '[\"新田ひより\",\"保科李沙\",\"白石晴香\",\"近藤玲奈\",\"守屋亨香\",\"日笠陽子\",\"巽悠衣子\",\"佐倉薫\",\"篠原侑\",\"田中貴子\",\"新田日阳里\",\"日笠阳子\",\"佐仓薰\",\"筱原侑\",\"田中贵子\"]', 1, '2026-02-09 23:41:26', '2026-03-18 17:59:57');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (109, '城下町的蒲公英', NULL, 'http://lain.bgm.tv/pic/cover/l/e4/00/117556_A0YTI.jpg', 'completed', '7.2', 12, 12, NULL, '樱田家是统治着樱田市的王族，家中九位兄弟姐妹各自拥有不同的超能力。为了选出下任国王，全市安装了200台摄像机进行24小时直播，让市民观看王子公主们的日常生活并投票。故事围绕三女茜的视角展开，描绘这个特殊家庭在公众注视下的温馨日常与成长故事。', '[\"校园\",\"日常\",\"喜剧\",\"超能力\",\"家庭\"]', '樱田家是一个拥有特殊能力的王室家族，九个兄弟姐妹通过遍布城市的监控摄像头参与王位竞选，日常生活充满欢笑与竞争。', NULL, NULL, '2015-07-02', '[\"花澤香菜\",\"茅野愛衣\",\"木村良平\",\"石原夏織\",\"松井恵理子\",\"村瀬歩\",\"小倉唯\",\"勝田詩織\",\"鈴木愛奈\",\"松本大\"]', '[\"花澤香菜\",\"茅野愛衣\",\"木村良平\",\"石原夏織\",\"松井恵理子\",\"村瀬歩\",\"小倉唯\",\"勝田詩織\",\"鈴木愛奈\",\"松本大\",\"花泽香菜\",\"茅野爱衣\",\"石原夏织\",\"松井惠理子\",\"村濑步\",\"小仓唯\",\"胜田诗织\",\"铃木爱奈\"]', 1, '2026-02-09 23:41:34', '2026-03-18 18:00:01');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (110, '魔女之旅', NULL, 'http://lain.bgm.tv/pic/cover/l/99/17/292970_mxMxx.jpg', 'completed', NULL, 12, 12, NULL, '故事讲述天才魔女伊蕾娜在获得“魔女”称号后，为了像儿时读过的旅行故事那样周游世界，踏上了漫长的旅程。在旅途中，她邂逅了形形色色的人与国家，经历了各种奇妙而深刻的事件，逐渐理解世界的多样性与人性的复杂。这部作品以单元剧形式展现了一个充满魔法与奇幻色彩的旅行物语。', '[\"奇幻\",\"冒险\",\"治愈\",\"旅行\"]', '年轻魔女伊蕾娜踏上旅程，游历各国，遇见形形色色的人与事，在旅途中成长与反思。', NULL, NULL, '2020-10-02', '[\"本渡楓\",\"花澤香菜\",\"黒沢ともよ\",\"小原好美\",\"日笠陽子\",\"Lynn\",\"佐藤利奈\",\"伊藤静\",\"上田麗奈\",\"楠木ともり\"]', '[\"本渡楓\",\"花澤香菜\",\"黒沢ともよ\",\"小原好美\",\"日笠陽子\",\"Lynn\",\"佐藤利奈\",\"伊藤静\",\"上田麗奈\",\"楠木ともり\",\"本渡枫\",\"花泽香菜\",\"黑泽朋世\",\"日笠阳子\",\"上田丽奈\",\"楠木灯\"]', 1, '2026-02-09 23:41:44', '2026-03-18 18:00:05');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (111, '为美好的世界献上祝福！', NULL, 'http://lain.bgm.tv/pic/cover/l/56/de/135275_G3liq.jpg', 'completed', '8.1', 10, 10, NULL, '热爱游戏的家里蹲少年佐藤和真因意外死亡后，被女神阿克娅带到异世界转生。他选择了阿克娅作为同伴，与中二病魔法师惠惠、妄想骑士达克妮丝组成问题队伍，在充满搞笑与混乱的异世界展开冒险。作品以反套路的方式解构异世界题材，充满无厘头笑料和角色间的爆笑互动。', '[\"异世界\",\"喜剧\",\"冒险\",\"奇幻\"]', '高中生佐藤和真意外死亡后，被女神阿克娅带到异世界，与问题队友们展开搞笑冒险。', NULL, NULL, '2016-01-13', '[\"福島潤\",\"雨宮天\",\"高橋李依\",\"茅野愛衣\",\"諏訪彩花\",\"堀江由衣\",\"原紗友里\",\"安元洋貴\",\"江口拓也\",\"稲田徹\"]', '[\"福島潤\",\"雨宮天\",\"高橋李依\",\"茅野愛衣\",\"諏訪彩花\",\"堀江由衣\",\"原紗友里\",\"安元洋貴\",\"江口拓也\",\"稲田徹\",\"福岛润\",\"雨宫天\",\"高桥李依\",\"茅野爱衣\",\"诹访彩花\",\"原纱友里\",\"安元洋贵\",\"稻田彻\"]', 1, '2026-02-09 23:41:52', '2026-03-18 18:00:08');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (112, '因为太怕痛就全点防御力了', NULL, 'http://lain.bgm.tv/pic/cover/l/c7/35/268545_yPJHc.jpg', 'completed', NULL, 12, 12, NULL, '少女本条枫在好友推荐下开始游玩VRMMO游戏《NewWorld Online》，因为害怕疼痛而将所有属性点都加在防御力上。凭借超高的防御力，她意外获得了各种稀有技能和装备，以“梅普露”的昵称在游戏中逐渐成为令人畏惧的“移动要塞”，与伙伴们展开了一段轻松有趣的冒险旅程。', '[\"游戏\",\"冒险\",\"喜剧\",\"奇幻\"]', '少女在虚拟现实游戏中因怕痛而将所有点数都加在防御力上，意外成为无敌的“移动要塞”，展开轻松有趣的冒险故事。', NULL, NULL, '2020-01-08', '[\"本渡楓\",\"野口瑠璃子\",\"杉山紀彰\",\"佐藤聡美\",\"早見沙織\",\"新井里美\",\"加隈亜衣\",\"諏訪ななか\",\"島袋美由利\",\"松井暁波\"]', '[\"本渡楓\",\"野口瑠璃子\",\"杉山紀彰\",\"佐藤聡美\",\"早見沙織\",\"新井里美\",\"加隈亜衣\",\"諏訪ななか\",\"島袋美由利\",\"松井暁波\",\"本渡枫\",\"杉山纪彰\",\"佐藤聪美\",\"早见沙织\",\"加隈亚衣\",\"诹访奈奈香\",\"岛袋美由利\",\"松井晓波\"]', 1, '2026-02-09 23:42:00', '2026-03-18 18:00:12');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (113, '一个人的○○小日子', NULL, 'http://lain.bgm.tv/pic/cover/l/9f/ab/241335_sLGll.jpg', 'completed', '7.0', 12, 12, NULL, '极度怕生的少女一里波知在小学毕业时，被唯一的朋友兼同学八原香依要求“在中学毕业前和全班同学成为朋友”。为了完成这个约定，波知开始了努力交朋友的校园生活。故事围绕波知与同学们之间温馨有趣的日常互动展开，描绘了她逐渐克服社交恐惧、收获友谊的成长历程。', '[\"校园\",\"日常\",\"治愈\",\"喜剧\"]', '极度害羞的女高中生一里波知为了与小学时的朋友重逢，努力结交新朋友的故事。', NULL, NULL, '2019-04-05', '[\"森下千咲\",\"田中美海\",\"鬼頭明里\",\"黒瀬ゆうこ\",\"市ノ瀬加那\",\"小原好美\",\"髙橋ミナミ\",\"春村奈々\",\"黒木ほの香\",\"宮下早紀\"]', '[\"森下千咲\",\"田中美海\",\"鬼頭明里\",\"黒瀬ゆうこ\",\"市ノ瀬加那\",\"小原好美\",\"髙橋ミナミ\",\"春村奈々\",\"黒木ほの香\",\"宮下早紀\",\"鬼头明里\",\"黑濑优子\",\"市之濑加那\",\"高桥美波\",\"春村奈奈\",\"黑木穗乃香\",\"宫下早纪\"]', 1, '2026-02-09 23:42:08', '2026-03-18 18:00:15');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (114, '黄金拼图 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/45/f9/100405_JrNQA.jpg', 'completed', '6.9', 12, 12, NULL, '本作是《黄金拼图》的第二季，继续讲述英国留学生爱丽丝与日本高中生大宫忍之间的温馨日常。故事围绕忍、爱丽丝、绫、阳子和可怜五位少女展开，描绘她们在校园与生活中的点点滴滴。通过文化差异带来的趣味互动和真挚友情，展现青春的美好与温暖。', '[\"校园\",\"日常\",\"治愈\",\"百合\",\"搞笑\"]', '英国留学生爱丽丝回到日本，与日本朋友们继续温馨有趣的校园生活，围绕文化差异和友情展开日常故事。', NULL, NULL, '2015-04-05', '[\"西明日香\",\"田中真奈美\",\"種田梨沙\",\"内山夕実\",\"東山奈央\",\"諏訪彩花\",\"潘めぐみ\",\"村川梨衣\",\"高橋美佳子\",\"木村亜希子\"]', '[\"西明日香\",\"田中真奈美\",\"種田梨沙\",\"内山夕実\",\"東山奈央\",\"諏訪彩花\",\"潘めぐみ\",\"村川梨衣\",\"高橋美佳子\",\"木村亜希子\",\"种田梨沙\",\"内山夕实\",\"东山奈央\",\"诹访彩花\",\"潘惠美\",\"高桥美佳子\",\"木村亚希子\"]', 1, '2026-02-09 23:45:00', '2026-03-18 18:00:18');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (115, '黄金拼图 Pretty Days', NULL, 'http://lain.bgm.tv/pic/cover/l/bd/98/175532_zNK2n.jpg', 'completed', '6.9', 1, 1, NULL, '《黄金拼图 Pretty Days》是《黄金拼图》系列的一部剧场版动画，于2016年上映。故事延续TV动画第二季的剧情，讲述忍、爱丽丝、绫、阳子和可怜五位少女在高中二年级的日常校园生活。影片以“文化祭”为主题，展现了她们为准备文化祭活动而忙碌的温馨日常，以及彼此之间深厚的友情。作品延续了系列一贯的轻松治愈风格，充满可爱的角色互动和细腻的情感描写。', '[\"校园\",\"日常\",\"治愈\",\"友情\",\"喜剧\"]', '《黄金拼图》的特别篇，讲述爱丽丝、阳子等五位女孩在高中毕业前夕的温馨日常故事，展现了她们之间的深厚友谊和美好回忆。', NULL, NULL, '2016-11-12', '[\"西明日香\",\"田中真奈美\",\"種田梨沙\",\"内山夕実\",\"東山奈央\",\"諏訪彩花\",\"潘めぐみ\",\"村川梨衣\",\"高橋美佳子\",\"田村ゆかり\"]', '[\"西明日香\",\"田中真奈美\",\"種田梨沙\",\"内山夕実\",\"東山奈央\",\"諏訪彩花\",\"潘めぐみ\",\"村川梨衣\",\"高橋美佳子\",\"田村ゆかり\",\"种田梨沙\",\"内山夕实\",\"东山奈央\",\"诹访彩花\",\"潘惠美\",\"高桥美佳子\",\"田村由香里\"]', 1, '2026-02-09 23:45:17', '2026-03-18 18:00:20');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (116, '轻音少女 剧场版', NULL, 'http://lain.bgm.tv/pic/cover/l/9e/3c/12426_vt490.jpg', 'completed', NULL, 1, 1, NULL, '樱丘高中轻音部四位成员在毕业前夕，决定前往伦敦进行毕业旅行。在异国他乡，她们不仅体验了英国文化，还意外获得在街头表演的机会。影片延续了TV版的温馨日常风格，通过音乐和友情展现了少女们面对毕业与未来的成长故事，最终以一场感人至深的告别演唱会收尾。', '[\"校园\",\"音乐\",\"日常\",\"治愈\"]', '轻音部五位成员在高中毕业后，决定前往伦敦进行毕业旅行，在异国他乡继续她们的音乐梦想和友情故事。', NULL, NULL, '2011-12-03', '[\"豊崎愛生\",\"日笠陽子\",\"佐藤聡美\",\"寿美菜子\",\"竹達彩奈\",\"藤東知夏\",\"米澤円\",\"真田アサミ\",\"永田依子\",\"夏樹リオ\"]', '[\"豊崎愛生\",\"日笠陽子\",\"佐藤聡美\",\"寿美菜子\",\"竹達彩奈\",\"藤東知夏\",\"米澤円\",\"真田アサミ\",\"永田依子\",\"夏樹リオ\",\"丰崎爱生\",\"日笠阳子\",\"佐藤聪美\",\"竹达彩奈\",\"藤东知夏\",\"米泽圆\",\"真田麻美\",\"夏树莉绪\"]', 1, '2026-02-09 23:45:25', '2026-03-18 18:00:23');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (117, '紫罗兰永恒花园', NULL, 'http://lain.bgm.tv/pic/cover/l/1e/e2/183878_Fef1o.jpg', 'completed', NULL, 13, 13, NULL, '故事发生在战后世界，讲述被称为“自动手记人偶”的少女薇尔莉特·伊芙加登，她曾是战场上冷酷的兵器。战后，她在CH邮政公司担任代笔人，通过为不同委托人写信，逐渐理解人类情感与“爱”的含义。在追寻已故少佐基尔伯特·布甘比利亚留下的“我爱你”话语真意的过程中，她开始学会感受并表达自己的情感。', '[\"治愈\",\"剧情\",\"奇幻\",\"战争\",\"成长\"]', '在战后世界中，曾是战争武器的少女薇尔莉特·伊芙加登成为自动手记人偶，通过代写书信理解人类情感，寻找“爱”的含义。', NULL, NULL, '2018-01-10', '[\"石川由依\",\"浪川大輔\",\"子安武人\",\"遠藤綾\",\"谢轶辉\",\"内山昂輝\",\"茅原実里\",\"戸松遥\",\"沢田敏子\",\"野坂尚也\"]', '[\"石川由依\",\"浪川大輔\",\"子安武人\",\"遠藤綾\",\"谢轶辉\",\"内山昂輝\",\"茅原実里\",\"戸松遥\",\"沢田敏子\",\"野坂尚也\",\"浪川大辅\",\"远藤绫\",\"内山昂辉\",\"茅原实里\",\"户松遥\",\"泽田敏子\"]', 1, '2026-02-09 23:49:25', '2026-03-18 18:00:27');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (118, '干物妹！小埋', NULL, 'http://lain.bgm.tv/pic/cover/l/41/2c/120187_nXjYb.jpg', 'completed', '7.1', 12, 12, NULL, '故事讲述在外是完美美少女高中生土间埋，回家后却变成披着仓鼠斗篷、沉迷游戏动漫的干物妹。她与哥哥土间太平的同居日常中，展现了在外光鲜与在家懒散的反差萌，以及兄妹间温馨有趣的互动。', '[\"日常\",\"喜剧\",\"校园\",\"兄妹\"]', '土间埋在学校是完美的高中生，回家后却变成沉迷游戏和动漫的干物妹，与哥哥土间太平的日常喜剧故事。', NULL, NULL, '2015-07-08', '[\"田中あいみ\",\"富田美憂\",\"野島健児\",\"影山灯\",\"白石晴香\",\"古川由利奈\",\"安元洋貴\",\"柿原徹也\",\"小清水亜美\",\"サンカクヘッド\"]', '[\"田中あいみ\",\"富田美憂\",\"野島健児\",\"影山灯\",\"白石晴香\",\"古川由利奈\",\"安元洋貴\",\"柿原徹也\",\"小清水亜美\",\"サンカクヘッド\",\"田中爱美\",\"富田美忧\",\"野岛健儿\",\"安元洋贵\",\"柿原彻也\",\"小清水亚美\"]', 1, '2026-02-09 23:49:32', '2026-03-18 18:00:30');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (119, '干物妹！小埋R', NULL, 'http://lain.bgm.tv/pic/cover/l/27/da/212775_as9It.jpg', 'completed', '7.1', 12, 12, NULL, '《干物妹！小埋R》是《干物妹！小埋》的第二季动画，继续讲述在外完美无缺、在家却变成宅女“小埋”的土间埋与哥哥太平的日常生活。本季中，小埋与好友海老名、切绘、希尔芬的互动更加深入，展现了更多温馨有趣的校园与家庭故事，同时太平的工作生活以及小埋的成长变化也成为剧情亮点。', '[\"日常\",\"喜剧\",\"校园\",\"治愈\"]', '外表完美的高中生土间埋，回家后却变成懒惰邋遢的干物妹，与哥哥太平的日常搞笑生活。', NULL, NULL, '2017-10-08', '[\"田中あいみ\",\"野島健児\",\"影山灯\",\"白石晴香\",\"古川由利奈\",\"安元洋貴\",\"柿原徹也\",\"小清水亜美\",\"水瀬いのり\",\"岡本信彦\"]', '[\"田中あいみ\",\"野島健児\",\"影山灯\",\"白石晴香\",\"古川由利奈\",\"安元洋貴\",\"柿原徹也\",\"小清水亜美\",\"水瀬いのり\",\"岡本信彦\",\"田中爱美\",\"野岛健儿\",\"安元洋贵\",\"柿原彻也\",\"小清水亚美\",\"水濑祈\",\"冈本信彦\"]', 1, '2026-02-09 23:49:45', '2026-03-18 18:00:33');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (120, '冰菓', NULL, 'http://lain.bgm.tv/pic/cover/l/cd/38/27364_1ZFmr.jpg', 'completed', '6.3', 22, 22, NULL, '故事发生在神山高中，奉行“节能主义”的高一学生折木奉太郎，在姐姐的要求下加入了濒临废社的“古籍研究社”。在那里他遇到了好奇心旺盛的千金小姐千反田爱瑠，她总是用“我很好奇”这句话来推动奉太郎解决各种校园谜团。随着社团成员福部里志和伊原摩耶花的加入，四人开始调查33年前“冰菓”事件背后的真相，逐渐揭开隐藏在平静校园生活中的秘密。', '[\"校园\",\"推理\",\"日常\",\"恋爱\"]', '节能主义高中生折木奉太郎被好奇心旺盛的千反田爱瑠卷入各种校园谜团，通过推理解决日常生活中的神秘事件。', NULL, NULL, '2012-04-22', '[\"中村悠一\",\"佐藤聡美\",\"阪口大助\",\"茅野愛衣\",\"置鮎龍太郎\",\"ゆきのさつき\",\"小山茉美\",\"ゆかな\",\"悠木碧\",\"豊崎愛生\"]', '[\"中村悠一\",\"佐藤聡美\",\"阪口大助\",\"茅野愛衣\",\"置鮎龍太郎\",\"ゆきのさつき\",\"小山茉美\",\"ゆかな\",\"悠木碧\",\"豊崎愛生\",\"佐藤聪美\",\"茅野爱衣\",\"置鲇龙太郎\",\"雪野五月\",\"由加奈\",\"丰崎爱生\"]', 1, '2026-02-09 23:49:54', '2026-03-18 18:00:36');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (121, '玉子爱情故事', NULL, 'http://lain.bgm.tv/pic/cover/l/59/8d/90880_NYUDd.jpg', 'completed', NULL, 1, 1, NULL, '《玉子爱情故事》是京都动画制作的剧场版动画，为电视动画《玉子市场》的续篇。故事聚焦于北白川玉子与青梅竹马大路饼藏之间的感情发展。在高中毕业前夕，饼藏终于鼓起勇气向玉子表白，而玉子也开始认真思考自己对饼藏的感情。影片细腻描绘了青春期少男少女面对爱情时的忐忑与成长，以及商店街伙伴们的温暖支持。', '[\"校园\",\"恋爱\",\"日常\",\"治愈\",\"青春\"]', '《玉子爱情故事》是京都动画制作的剧场版动画，是电视动画《玉子市场》的续作。故事聚焦于北白川玉子和饼藏之间逐渐发展的感情，描绘了他们在高中毕业前夕面对未来和彼此心意的成长故事。', NULL, NULL, '2014-04-26', '[\"洲崎綾\",\"升望\",\"田丸篤志\",\"金子有希\",\"長妻樹里\",\"山下百合恵\",\"日高里菜\",\"藤原啓治\",\"日笠陽子\",\"西村知道\"]', '[\"洲崎綾\",\"升望\",\"田丸篤志\",\"金子有希\",\"長妻樹里\",\"山下百合恵\",\"日高里菜\",\"藤原啓治\",\"日笠陽子\",\"西村知道\",\"洲崎绫\",\"田丸笃志\",\"长妻树里\",\"山下百合惠\",\"藤原启治\",\"日笠阳子\"]', 1, '2026-02-09 23:50:04', '2026-03-18 18:00:39');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (122, '打工吧！魔王大人', NULL, 'http://lain.bgm.tv/pic/cover/l/f7/11/330057_wMWZn.jpg', 'completed', NULL, 13, 13, NULL, '魔王撒旦在征服世界的最后关头被勇者艾米莉亚击败，被迫逃往异世界日本东京。为了生存，他与部下路西菲尔在快餐店打工，过着普通人的生活。勇者艾米莉亚也追踪至此，却因魔力耗尽无法使用魔法，只能在电信公司当客服。三人在现代社会中展开了一段充满反差萌的奇幻日常喜剧。', '[\"奇幻\",\"喜剧\",\"日常\",\"职场\",\"异世界\"]', '魔王撒旦在现代日本打工生活的喜剧故事。', NULL, NULL, '2013-04-04', '[\"逢坂良太\",\"日笠陽子\",\"小野友樹\",\"下野紘\",\"東山奈央\",\"伊藤かな恵\",\"浅倉杏美\",\"西明日香\",\"井口祐一\",\"安元洋貴\"]', '[\"逢坂良太\",\"日笠陽子\",\"小野友樹\",\"下野紘\",\"東山奈央\",\"伊藤かな恵\",\"浅倉杏美\",\"西明日香\",\"井口祐一\",\"安元洋貴\",\"日笠阳子\",\"小野友树\",\"下野纮\",\"东山奈央\",\"伊藤加奈惠\",\"浅仓杏美\",\"安元洋贵\"]', 1, '2026-02-09 23:50:23', '2026-03-18 18:00:42');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (123, '小林家的龙女仆', NULL, 'http://lain.bgm.tv/pic/cover/l/e9/15/179949_c2j50.jpg', 'completed', '7.9', 13, 13, NULL, '普通程序员小林偶然救下了一条名叫托尔的龙，为报答救命之恩，托尔化身为女仆住进小林家。故事围绕小林与托尔及其他龙族伙伴的日常生活展开，描绘了人类与龙族之间温馨有趣的跨种族同居生活。', '[\"日常\",\"喜剧\",\"奇幻\",\"治愈\"]', '普通上班族小林某天救了一条名叫托尔的龙，托尔为了报恩变成女仆住进小林家，引发了一系列温馨有趣的日常故事。', NULL, NULL, '2017-01-11', '[\"田村睦心\",\"常蓉珊\",\"桑原由気\",\"钱琛\",\"長縄まりあ\",\"沈欣如\",\"高田憂希\",\"贺文潇\",\"髙橋ミナミ\",\"李诗萌\"]', '[\"田村睦心\",\"常蓉珊\",\"桑原由気\",\"钱琛\",\"長縄まりあ\",\"沈欣如\",\"高田憂希\",\"贺文潇\",\"髙橋ミナミ\",\"李诗萌\",\"桑原由气\",\"长绳麻理亚\",\"高田忧希\",\"高桥美波\"]', 1, '2026-02-09 23:50:30', '2026-03-18 18:00:46');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (124, '小林家的龙女仆S', NULL, 'http://lain.bgm.tv/pic/cover/l/17/ed/274234_iZ22k.jpg', 'completed', '8.2', 12, 12, NULL, '《小林家的龙女仆》第二季，继续讲述程序员小林与龙女仆托尔等异世界生物的温馨日常。本季中，新的龙族角色伊露露加入，带来更多欢笑与感动。故事围绕小林与托尔逐渐加深的羁绊、康娜的校园生活以及龙族与人类共存的温馨故事展开，充满治愈与幽默。', '[\"日常\",\"喜剧\",\"奇幻\",\"治愈\"]', '小林家的龙女仆第二季，讲述程序员小林与龙女仆托尔等龙族伙伴的日常生活，新角色伊露露加入后带来更多温馨搞笑的故事。', NULL, NULL, '2021-07-07', '[\"田村睦心\",\"常蓉珊\",\"桑原由気\",\"钱琛\",\"長縄まりあ\",\"沈欣如\",\"嶺内ともみ\",\"月夜桥\",\"高田憂希\",\"贺文潇\"]', '[\"田村睦心\",\"常蓉珊\",\"桑原由気\",\"钱琛\",\"長縄まりあ\",\"沈欣如\",\"嶺内ともみ\",\"月夜桥\",\"高田憂希\",\"贺文潇\",\"桑原由气\",\"长绳麻理亚\",\"岭内知美\",\"高田忧希\"]', 1, '2026-02-09 23:50:40', '2026-03-18 18:00:51');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (125, 'ENDRO～！', NULL, 'http://lain.bgm.tv/pic/cover/l/02/9d/254895_tq0Vx.jpg', 'completed', '6.9', 12, 12, NULL, '在和平的魔法王国，魔王已被勇者击败，世界恢复了安宁。然而，勇者学校的优等生玛娜和她的伙伴们——战士尤夏、魔法师赛拉和僧侣法伊——在毕业考试中意外召唤出了幼年魔王，导致时间倒流，她们不得不重新开始冒险之旅。这部作品以轻松幽默的方式描绘了四位少女在充满奇幻色彩的世界中，一边学习成为真正的勇者，一边享受日常生活的温馨故事。', '[\"奇幻\",\"日常\",\"喜剧\",\"校园\",\"冒险\"]', '在和平的魔法世界，四位少女梦想成为勇者，但她们的老师意外变成了魔王，引发了一系列搞笑冒险。', NULL, NULL, '2019-01-12', '[\"赤尾ひかる\",\"夏川椎菜\",\"小澤亜李\",\"水瀬いのり\",\"久野美咲\",\"玄田哲章\",\"麻倉もも\",\"種﨑敦美\",\"西明日香\",\"佐藤聡美\"]', '[\"赤尾ひかる\",\"夏川椎菜\",\"小澤亜李\",\"水瀬いのり\",\"久野美咲\",\"玄田哲章\",\"麻倉もも\",\"種﨑敦美\",\"西明日香\",\"佐藤聡美\",\"赤尾光\",\"小泽亚李\",\"水濑祈\",\"麻仓桃\",\"种崎敦美\",\"佐藤聪美\"]', 1, '2026-02-09 23:50:48', '2026-03-18 18:00:56');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (126, '埃罗芒阿老师', NULL, 'http://lain.bgm.tv/pic/cover/l/87/bf/172498_wfm40.jpg', 'completed', NULL, 12, 12, NULL, '高中生兼轻小说作家和泉正宗与同住一个屋檐下的妹妹和泉纱雾，纱雾是个家里蹲，以“埃罗芒阿老师”为笔名担任正宗小说的插画师。正宗为了与纱雾拉近距离，努力创作小说，两人在共同创作中逐渐加深了解，展开一段温馨又略带尴尬的兄妹日常故事。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"轻小说改编\"]', '高中生小说家高坂京介发现自己的妹妹高坂桐乃竟是知名情色漫画插画师“埃罗芒阿老师”，两人在隐瞒身份的情况下开始合作创作轻小说，并逐渐发展出超越兄妹的感情。', NULL, NULL, '2017-04-08', '[\"松岡禎丞\",\"藤田茜\",\"髙橋ミナミ\",\"大西沙織\",\"木戸衣吹\",\"石川由依\",\"小松未可子\",\"島﨑信長\",\"山下誠一郎\",\"井口裕香\"]', '[\"松岡禎丞\",\"藤田茜\",\"髙橋ミナミ\",\"大西沙織\",\"木戸衣吹\",\"石川由依\",\"小松未可子\",\"島﨑信長\",\"山下誠一郎\",\"井口裕香\",\"松冈祯丞\",\"高桥美波\",\"大西沙织\",\"木户衣吹\",\"岛崎信长\",\"山下诚一郎\"]', 1, '2026-02-09 23:50:58', '2026-03-18 18:00:58');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (127, '我的青春恋爱物语果然有问题', NULL, 'http://lain.bgm.tv/pic/cover/l/1e/f1/54433_JZ99l.jpg', 'completed', NULL, 13, 13, NULL, '高中生比企谷八幡性格孤僻，对青春恋爱喜剧抱有扭曲看法。在老师平冢静的推荐下，他加入了侍奉部，与完美少女雪之下雪乃和活泼开朗的由比滨结衣相遇。三人通过解决他人的烦恼，逐渐理解彼此，展开了一段充满误解与成长的青春故事。', '[\"校园\",\"恋爱\",\"日常\",\"喜剧\",\"轻小说改编\"]', '高中生比企谷八幡性格孤僻，被老师强迫加入“侍奉部”，与完美少女雪之下雪乃和活泼女孩由比滨结衣一起解决同学的各种问题，逐渐改变对人际关系的看法。', NULL, NULL, '2013-04-04', '[\"江口拓也\",\"早見沙織\",\"東山奈央\",\"小松未可子\",\"檜山修之\",\"悠木碧\",\"柚木涼香\",\"中原麻衣\",\"近藤隆\",\"井上麻里奈\"]', '[\"江口拓也\",\"早見沙織\",\"東山奈央\",\"小松未可子\",\"檜山修之\",\"悠木碧\",\"柚木涼香\",\"中原麻衣\",\"近藤隆\",\"井上麻里奈\",\"早见沙织\",\"东山奈央\",\"桧山修之\",\"柚木凉香\"]', 1, '2026-02-09 23:51:07', '2026-03-18 18:01:02');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (128, '我的青春恋爱物语果然有问题 续', NULL, 'http://lain.bgm.tv/pic/cover/l/1e/ef/102134_luzUc.jpg', 'completed', NULL, 13, 13, NULL, '本作是《我的青春恋爱物语果然有问题》的第二季，继续讲述比企谷八幡、雪之下雪乃和由比滨结衣在侍奉部的校园生活。随着文化祭的临近，三人之间的关系变得更加复杂微妙，八幡继续用他独特的“自爆”方式解决问题，却逐渐意识到自己内心真实的情感。故事深入探讨了青春期少男少女的自我认知、人际关系与成长烦恼。', '[\"校园\",\"恋爱\",\"日常\",\"轻小说改\",\"青春\"]', '高中生比企谷八幡继续在侍奉部解决各种委托，与雪之下雪乃、由比滨结衣的关系逐渐发展，面对青春期的情感与成长问题。', NULL, NULL, '2015-04-02', '[\"江口拓也\",\"早見沙織\",\"東山奈央\",\"佐倉綾音\",\"悠木碧\",\"小松未可子\",\"近藤隆\",\"井上麻里奈\",\"ささきのぞみ\",\"小清水亜美\"]', '[\"江口拓也\",\"早見沙織\",\"東山奈央\",\"佐倉綾音\",\"悠木碧\",\"小松未可子\",\"近藤隆\",\"井上麻里奈\",\"ささきのぞみ\",\"小清水亜美\",\"早见沙织\",\"东山奈央\",\"佐仓绫音\",\"佐佐木望\",\"小清水亚美\"]', 1, '2026-02-09 23:51:15', '2026-03-18 18:01:05');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (129, '笨蛋、测验、召唤兽', NULL, 'http://lain.bgm.tv/pic/cover/l/db/a1/3326_lwy94.jpg', 'completed', NULL, 12, 12, NULL, '文月学园采用根据考试成绩分班的制度，F班学生吉井明久为了改善班级待遇，与召唤兽系统展开一系列搞笑对决。故事围绕明久与姬路瑞希、岛田美波等同学的校园生活，通过测验召唤战争展现青春喜剧。', '[\"校园\",\"喜剧\",\"恋爱\",\"轻小说改编\"]', '在一所根据考试成绩分配班级和设备的学校里，F班的学生们使用召唤兽进行班级战争，试图改善自己的学习环境。', NULL, NULL, '2010-01-06', '[\"下野紘\",\"原田ひとみ\",\"水橋かおり\",\"加藤英美里\",\"鈴木達央\",\"宮田幸季\",\"磯村知美\",\"竹達彩奈\",\"寺島拓篤\",\"南條愛乃\"]', '[\"下野紘\",\"原田ひとみ\",\"水橋かおり\",\"加藤英美里\",\"鈴木達央\",\"宮田幸季\",\"磯村知美\",\"竹達彩奈\",\"寺島拓篤\",\"南條愛乃\",\"下野纮\",\"原田瞳\",\"水桥香织\",\"铃木达央\",\"宫田幸季\",\"矶村知美\",\"竹达彩奈\",\"寺岛拓笃\",\"南条爱乃\"]', 1, '2026-02-09 23:51:23', '2026-03-18 18:01:08');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (130, '笨蛋、测验、召唤兽 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/7e/8d/11145_6s6G6.jpg', 'completed', '7.7', 13, 13, NULL, '在文月学园，学生根据考试成绩被分配到不同等级的班级，并可使用“召唤兽”进行班级间的战斗。主角吉井明久所在的F班是最差的班级，他们为了改善学习环境，不断向其他班级发起挑战。第二季延续了第一季的搞笑校园生活，明久与姬路瑞希、岛田美波等同学继续展开各种爆笑的日常，同时班级间的召唤兽战斗也更加激烈。', '[\"校园\",\"搞笑\",\"恋爱\",\"日常\",\"轻小说改编\"]', '笨蛋、测验、召唤兽第二季继续讲述文月学园的故事，学生们通过召唤兽进行测验战争，争夺更好的教室和设备。主角吉井明久和朋友们在搞笑日常中面对各种挑战，包括恋爱、友情和学业竞争。', NULL, NULL, '2011-07-07', '[\"下野紘\",\"原田ひとみ\",\"水橋かおり\",\"加藤英美里\",\"平田真菜\",\"鈴木達央\",\"宮田幸季\",\"磯村知美\",\"三石琴乃\",\"五十嵐裕美\"]', '[\"下野紘\",\"原田ひとみ\",\"水橋かおり\",\"加藤英美里\",\"平田真菜\",\"鈴木達央\",\"宮田幸季\",\"磯村知美\",\"三石琴乃\",\"五十嵐裕美\",\"下野纮\",\"原田瞳\",\"水桥香织\",\"铃木达央\",\"宫田幸季\",\"矶村知美\",\"五十岚裕美\"]', 1, '2026-02-09 23:51:34', '2026-03-18 18:01:10');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (131, '属性咖啡厅', NULL, 'http://lain.bgm.tv/pic/cover/l/f4/fe/204145_mbsLs.jpg', 'completed', NULL, 12, 12, NULL, '故事讲述女高中生樱之宫莓香在寻找兼职时，偶然进入了一家名为“Stile”的咖啡厅。这家咖啡厅的特色是服务员会根据客人的喜好扮演不同属性的角色。莓香因为天生眼神凶狠，被店长指派扮演“抖S”属性。在咖啡厅工作的过程中，她结识了性格各异的同事，并逐渐适应了这份特殊的工作，展开了一系列轻松有趣的日常故事。', '[\"日常\",\"喜剧\",\"职场\",\"校园\"]', '一家名为属性咖啡厅的店铺，员工们各自拥有不同的属性能力，为顾客提供独特的服务体验。', NULL, NULL, '2017-10-07', '[\"和氣あず未\",\"鬼頭明里\",\"春野杏\",\"種﨑敦美\",\"徳井青空\",\"前野智昭\",\"鈴木達央\",\"松嵜麗\"]', '[\"和氣あず未\",\"鬼頭明里\",\"春野杏\",\"種﨑敦美\",\"徳井青空\",\"前野智昭\",\"鈴木達央\",\"松嵜麗\",\"和气杏未\",\"鬼头明里\",\"种崎敦美\",\"德井青空\",\"铃木达央\",\"松嵜丽\"]', 1, '2026-02-09 23:51:44', '2026-03-18 18:01:14');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (132, '男子高中生的日常', NULL, 'http://lain.bgm.tv/pic/cover/l/c5/73/24790_4wdXB.jpg', 'completed', '8.2', 12, 12, NULL, '故事围绕三名普通男子高中生——忠邦、吉竹和秀则的日常生活展开。他们每天在学校里做着各种无聊又搞笑的蠢事，比如模仿动漫角色、讨论奇怪的话题、恶作剧等。作品以单元剧形式呈现，通过夸张的喜剧手法描绘青春期男生特有的友情、烦恼和天马行空的想象力，展现了看似平凡却充满笑料的校园生活。', '[\"校园\",\"日常\",\"喜剧\",\"搞笑\"]', '故事围绕三名普通男子高中生——忠邦、秀则和吉竹的日常生活展开，描绘他们在学校、家庭和社区中发生的各种搞笑、荒诞又充满青春气息的趣事。', NULL, NULL, '2012-01-09', '[\"入野自由\",\"三瓶由布子\",\"杉田智和\",\"鈴村健一\",\"日笠陽子\",\"高垣彩陽\",\"悠木碧\",\"浪川大輔\",\"小野友樹\",\"石田彰\"]', '[\"入野自由\",\"三瓶由布子\",\"杉田智和\",\"鈴村健一\",\"日笠陽子\",\"高垣彩陽\",\"悠木碧\",\"浪川大輔\",\"小野友樹\",\"石田彰\",\"铃村健一\",\"日笠阳子\",\"高垣彩阳\",\"浪川大辅\",\"小野友树\"]', 1, '2026-02-09 23:52:00', '2026-03-18 18:01:18');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (133, '女高中生的虚度日常', NULL, 'http://lain.bgm.tv/pic/cover/l/f3/d0/265708_QDkDe.jpg', 'completed', '5.8', 12, 12, NULL, '故事围绕三名性格迥异的女高中生展开：自称“笨蛋”的田中望、沉迷BL的菊池茜以及面无表情的才女鹭宫诗织。她们在女子高中里度过看似“虚度”却充满欢笑与感动的日常，通过各种荒诞又温馨的校园生活片段，展现青春期的友情、成长与自我认知。', '[\"校园\",\"日常\",\"喜剧\",\"友情\"]', '三名性格迥异的女高中生——自称“机器人”的严肃学霸、沉迷幻想的“笨蛋”和自称“萝莉”的宅女，在高中日常中发生的一系列搞笑故事，展现了青春的无厘头与友谊。', NULL, NULL, '2019-07-05', '[\"赤﨑千夏\",\"戸松遥\",\"豊崎愛生\",\"長縄まりあ\",\"富田美憂\",\"高橋李依\",\"佐藤聡美\",\"M・A・O\",\"興津和幸\",\"上田麗奈\"]', '[\"赤﨑千夏\",\"戸松遥\",\"豊崎愛生\",\"長縄まりあ\",\"富田美憂\",\"高橋李依\",\"佐藤聡美\",\"M・A・O\",\"興津和幸\",\"上田麗奈\",\"赤崎千夏\",\"户松遥\",\"丰崎爱生\",\"长绳麻理亚\",\"富田美忧\",\"高桥李依\",\"佐藤聪美\",\"兴津和幸\",\"上田丽奈\"]', 1, '2026-02-09 23:52:09', '2026-03-18 18:01:21');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (134, '街角魔族', NULL, 'http://lain.bgm.tv/pic/cover/l/af/22/272510_BZ00p.jpg', 'completed', NULL, 12, 12, NULL, '普通女高中生吉田优子某天突然觉醒了魔族血脉，并被告知必须打倒光之一族的魔法少女千代田桃。然而桃却是个温柔善良的女孩，不仅没有敌意还处处帮助优子。两人在打打闹闹的日常中逐渐建立起奇妙的友谊，优子也开始接受自己作为魔族后裔的身份，与伙伴们展开温馨有趣的校园生活。', '[\"日常\",\"喜剧\",\"校园\",\"奇幻\",\"百合\"]', '普通女高中生吉田优子某天突然觉醒了魔族血脉，获得了神秘力量，并与魔法少女千代田桃展开了一段既敌对又合作的奇妙关系。', NULL, NULL, '2019-07-11', '[\"小原好美\",\"鬼頭明里\",\"髙橋ミナミ\",\"高柳知葉\",\"千本木彩花\",\"諏訪彩花\",\"大和田仁美\",\"大原さやか\",\"仲野裕\",\"七瀬彩夏\"]', '[\"小原好美\",\"鬼頭明里\",\"髙橋ミナミ\",\"高柳知葉\",\"千本木彩花\",\"諏訪彩花\",\"大和田仁美\",\"大原さやか\",\"仲野裕\",\"七瀬彩夏\",\"鬼头明里\",\"高桥美波\",\"高柳知叶\",\"诹访彩花\",\"大原沙耶香\",\"七濑彩夏\"]', 1, '2026-02-09 23:52:18', '2026-03-18 18:01:23');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (135, '街角魔族 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/ef/d3/313852_550li.jpg', 'completed', '7.4', 12, 12, NULL, '在魔族少女吉田优子与魔法少女千代田桃的日常中，两人继续着奇妙的同居生活。随着优子逐渐觉醒更多魔族力量，她们的关系也从敌对转变为微妙的友情。本季中，优子开始探索自己的魔族身世，而桃则继续暗中保护着她，两人共同面对新的魔法生物和日常挑战，温馨又搞笑的校园奇幻故事继续上演。', '[\"日常\",\"奇幻\",\"校园\",\"喜剧\",\"百合\"]', '普通女高中生吉田优子某天突然觉醒了魔族血脉，与魔法少女千代田桃相遇后，两人在日常生活与魔族使命之间展开了一系列温馨有趣的互动故事。', NULL, NULL, '2022-04-07', '[\"Zhang, Huilin\",\"He, Wenxiao\"]', '[\"Zhang, Huilin\",\"He, Wenxiao\",\"张惠霖\",\"何文晓\"]', 1, '2026-02-09 23:52:26', '2026-03-18 18:01:26');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (136, '赛马娘 Pretty Derby 第一季', NULL, 'http://lain.bgm.tv/pic/cover/l/1c/6b/315574_tLgrT.jpg', 'completed', NULL, 13, 13, NULL, '在赛马娘的世界里，拥有马匹血统的少女们以成为顶级偶像赛马娘为目标。特别周是一位从乡下来到都市的赛马娘，她立志要成为日本第一的赛马娘。在训练员和同伴们的帮助下，她不断成长，参加各种比赛和偶像活动，追逐自己的梦想。作品结合了赛马竞技与偶像养成元素，展现了少女们努力奋斗的青春故事。', '[\"运动\",\"偶像\",\"日常\",\"竞技\",\"校园\"]', '故事讲述赛马娘们为了成为顶级偶像而奋斗，她们在特雷森学园接受训练，参加比赛和演出，实现梦想。', NULL, NULL, '2021-01-04', '[\"Machico\",\"大西沙織\",\"沖野晃司\",\"和氣あず未\",\"高野麻里佳\",\"大橋彩香\",\"木村千咲\",\"上田瞳\",\"田所あずさ\",\"前田佳織里\"]', '[\"Machico\",\"大西沙織\",\"沖野晃司\",\"和氣あず未\",\"高野麻里佳\",\"大橋彩香\",\"木村千咲\",\"上田瞳\",\"田所あずさ\",\"前田佳織里\",\"大西沙织\",\"冲野晃司\",\"和气杏未\",\"大桥彩香\",\"田所梓\",\"前田佳织里\"]', 1, '2026-02-09 23:52:35', '2026-03-18 18:01:30');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (137, '22/7', '22/7', 'https://cdn.myanimelist.net/images/anime/1485/108385l.jpg', 'completed', '6.8', 12, 12, 24, '八位少女突然收到神秘组织“G.I.P”的邀请，被告知她们被选中成为虚拟偶像组合“22/7”的成员。在完全封闭的设施中，她们必须接受严格的训练，面对内心的迷茫与挑战，同时探索自己成为偶像的意义。随着演出的临近，少女们逐渐揭开组织背后的秘密，并在追梦过程中建立起深厚的羁绊。', '[\"偶像\",\"音乐\",\"日常\",\"成长\"]', '八位少女被神秘组织选中，组成虚拟偶像团体22/7，在严格的训练和任务中探索自我与梦想的故事。', NULL, NULL, '2020-01-11', '[\"Amaki, Sally\",\"Kuraoka, Mizuha\",\"Shirosawa, Kanae\",\"Kawase, Uta\",\"Chiharu\",\"Miyase, Reina\",\"Saijou, Nagomi\",\"Yoshimiya, Ruri\",\"Koyasu, Takehito\",\"Tsunematsu, Ayumi\"]', '[\"Amaki, Sally\",\"Kuraoka, Mizuha\",\"Shirosawa, Kanae\",\"Kawase, Uta\",\"Chiharu\",\"Miyase, Reina\",\"Saijou, Nagomi\",\"Yoshimiya, Ruri\",\"Koyasu, Takehito\",\"Tsunematsu, Ayumi\",\"天城莎莉\",\"藏冈瑞叶\",\"白泽早苗\",\"川濑歌\",\"宫濑玲奈\",\"西条和\",\"吉宫瑠璃\",\"子安武人\",\"常松步\"]', 1, '2026-02-09 23:56:27', '2026-03-18 18:01:32');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (138, 'Love Live! 虹咲学园学园偶像同好会', NULL, 'http://lain.bgm.tv/pic/cover/l/a7/35/296659_o709D.jpg', 'completed', '7.5', 13, 13, NULL, '位于东京台场的虹咲学园是一所自由奔放的学校。在这里，没有像μ\'s和Aqours那样的“学园偶像同好会”，而是每个成员都以个人身份活动的“学园偶像同好会”。故事讲述了高咲侑与10位个性鲜明的学园偶像相遇，共同追求梦想的青春物语。她们各自拥有独特的风格和魅力，在舞台上闪耀着属于自己的光芒。', '[\"校园\",\"音乐\",\"偶像\",\"日常\",\"青春\"]', '虹咲学园的学生们为了追求各自的梦想，成立了学园偶像同好会，通过音乐和表演展现自我，共同成长的故事。', NULL, NULL, '2020-10-03', '[\"Kubota, Miyu\",\"Kitou, Akari\",\"Murakami, Natsumi\",\"Sagara, Mayu\",\"Maeda, Kaori\",\"Yano, Hinaki\",\"Tanaka, Chiemi\",\"Onishi, Aguri\",\"Sashide, Maria\",\"Kusunoki, Tomori\"]', '[\"Kubota, Miyu\",\"Kitou, Akari\",\"Murakami, Natsumi\",\"Sagara, Mayu\",\"Maeda, Kaori\",\"Yano, Hinaki\",\"Tanaka, Chiemi\",\"Onishi, Aguri\",\"Sashide, Maria\",\"Kusunoki, Tomori\",\"久保田未梦\",\"鬼头明里\",\"村上奈津实\",\"相良茉优\",\"前田佳织里\",\"矢野妃菜喜\",\"田中千惠美\",\"大西亚玖璃\",\"指出毬亚\",\"楠木灯\"]', 1, '2026-02-09 23:56:39', '2026-03-18 18:01:35');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (139, 'Love Live! Sunshine!!', 'ラブライブ！サンシャイン!!', 'https://cdn.myanimelist.net/images/anime/8/80791l.jpg', 'completed', '7.4', 13, 13, 24, '故事发生在静冈县沼津市的海边小镇内浦，私立浦之星女子学院面临废校危机。以高海千歌为首的九位少女受到μ\'s的启发，决定成立校园偶像团体“Aqours”，通过偶像活动来拯救学校。她们在追逐梦想的过程中，不仅要面对学校存续的挑战，还要参加“Love Live!”大赛，与全国各地的校园偶像团体竞争。', '[\"校园\",\"偶像\",\"音乐\",\"励志\",\"日常\"]', '在静冈县沼津市的海边小镇，高中二年级学生高海千歌受到偶像团体μ\'s的启发，与八位同学一起成立了校园偶像团体Aqours，追逐梦想的故事。', NULL, NULL, '2016-07-02', '[\"Takatsuki, Kanako\",\"Furihata, Ai\",\"Komiya, Arisa\",\"Suwa, Nanaka\",\"Suzuki, Aina\",\"Aida, Rikako\",\"Inami, Anju\",\"Kobayashi, Aika\",\"Saitou, Shuka\",\"Takamori, Natsumi\"]', '[\"Takatsuki, Kanako\",\"Furihata, Ai\",\"Komiya, Arisa\",\"Suwa, Nanaka\",\"Suzuki, Aina\",\"Aida, Rikako\",\"Inami, Anju\",\"Kobayashi, Aika\",\"Saitou, Shuka\",\"Takamori, Natsumi\",\"高槻加奈子\",\"降幡爱\",\"小宫有纱\",\"诹访奈奈香\",\"铃木爱奈\",\"相田丽香\",\"伊波杏树\",\"小林爱香\",\"斋藤朱夏\",\"高森奈津美\"]', 1, '2026-02-09 23:56:48', '2026-03-18 18:01:40');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (141, 'Love Live! 超级明星!!', NULL, 'https://cdn.myanimelist.net/images/anime/1758/115692l.jpg', 'completed', '6.1', 12, 12, NULL, '涩谷香音在东京涩谷的结丘女子高等学校入学，原本对唱歌没有自信的她，在校园里遇到了想要成为学园偶像的唐可可。受到可可的热情感染，香音决定一起组建学园偶像团体，与陆续加入的成员们一起追逐梦想，挑战Love Live大赛。', '[\"校园\",\"音乐\",\"偶像\",\"日常\",\"励志\"]', '故事发生在东京涩谷的私立结丘女子高等学校，新生涩谷香音在入学第一天就遇到了想成为学园偶像的唐可可。在可可的鼓励下，香音决定与她一起组建学园偶像团体，并招募更多成员，目标是成为最闪耀的学园偶像。', NULL, NULL, '2021-07-11', '[\"Suzuoki, Hirotaka\",\"Shimada, Bin\"]', '[\"Suzuoki, Hirotaka\",\"Shimada, Bin\",\"铃置洋孝\",\"岛田敏\"]', 1, '2026-02-09 23:57:05', '2026-03-18 18:01:43');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (142, 'NEW GAME!', NULL, 'https://cdn.myanimelist.net/images/anime/4/86790l.jpg', 'completed', '7.7', 12, 12, NULL, '高中毕业的凉风青叶进入了她梦寐以求的游戏公司“飞鹰跃动”，成为了一名游戏角色设计师。作为新人，她在充满个性的前辈们指导下，努力适应职场生活，参与公司新作《精灵物语3》的开发工作。这部作品描绘了游戏开发行业的日常，展现了青叶与同事们一起克服困难、共同成长的温馨故事。', '[\"职场\",\"日常\",\"萌系\",\"游戏开发\"]', '高中毕业后，凉风青叶进入了她梦想的游戏公司工作，作为新人角色设计师，在充满活力的同事们的帮助下，努力适应职场生活并追逐自己的梦想。', NULL, NULL, '2017-07-11', '[\"Takada, Yuuki\",\"Hikasa, Youko\",\"Morinaga, Chitose\",\"Wakui, Yuu\",\"Miyake, Kenta\",\"Kitamura, Eri\",\"Iwami, Manaka\",\"Matsuda, Risae\",\"Kawakami, Chihiro\",\"Takeo, Ayumi\"]', '[\"Takada, Yuuki\",\"Hikasa, Youko\",\"Morinaga, Chitose\",\"Wakui, Yuu\",\"Miyake, Kenta\",\"Kitamura, Eri\",\"Iwami, Manaka\",\"Matsuda, Risae\",\"Kawakami, Chihiro\",\"Takeo, Ayumi\",\"高田忧希\",\"日笠阳子\",\"森永千才\",\"和久井优\",\"三宅健太\",\"喜多村英梨\",\"石见舞菜香\",\"松田利冴\",\"川上千寻\",\"竹尾步美\"]', 1, '2026-02-10 00:03:15', '2026-03-18 18:01:46');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (143, 'NEW GAME!! 第二季', NULL, 'https://cdn.myanimelist.net/images/anime/4/86790l.jpg', 'completed', '7.7', 12, 12, NULL, '《NEW GAME!!》是《NEW GAME》的第二季动画，改编自得能正太郎创作的四格漫画。故事继续讲述高中毕业后进入游戏公司“飞鹰跃动”工作的凉风青叶，在第二季中她已成为能够独当一面的角色设计师，并开始指导新人。本季聚焦于青叶与同事们共同开发新游戏《PECO》的过程，展现了游戏开发行业的日常、团队合作与个人成长，充满温馨的职场喜剧氛围。', '[\"职场\",\"日常\",\"喜剧\",\"萌系\",\"游戏开发\"]', '《NEW GAME!!》是《NEW GAME》的第二季，继续讲述游戏公司Eagle Jump的日常故事。主角青叶和同事们继续开发新游戏，面对工作挑战和人际关系，展现职场新人的成长与友情。', NULL, NULL, '2017-07-11', '[\"Takada, Yuuki\",\"Hikasa, Youko\",\"Morinaga, Chitose\",\"Wakui, Yuu\",\"Miyake, Kenta\",\"Kitamura, Eri\",\"Iwami, Manaka\",\"Matsuda, Risae\",\"Kawakami, Chihiro\",\"Takeo, Ayumi\"]', '[\"Takada, Yuuki\",\"Hikasa, Youko\",\"Morinaga, Chitose\",\"Wakui, Yuu\",\"Miyake, Kenta\",\"Kitamura, Eri\",\"Iwami, Manaka\",\"Matsuda, Risae\",\"Kawakami, Chihiro\",\"Takeo, Ayumi\",\"高田忧希\",\"高田有希\",\"日笠阳子\",\"森永千才\",\"三宅健太\",\"喜多村英梨\",\"石见舞菜香\",\"川上伦子\"]', 1, '2026-02-10 00:03:25', '2026-03-18 18:01:51');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (144, '月が導く異世界道中', NULL, 'http://lain.bgm.tv/pic/cover/l/26/ea/317275_t23SU.jpg', 'completed', '7.7', 12, 12, NULL, '高中生深澄真被召唤到异世界，却因外貌被女神嫌弃而流放荒野。在月亮的指引下，他凭借现代知识和特殊能力，在异世界建立自己的家园，并与龙族、精灵等种族相遇，逐渐改变这个世界的命运。', '[\"异世界\",\"冒险\",\"奇幻\",\"转生\"]', '一名普通高中生被月亮引导穿越到异世界，开始了一段充满冒险与成长的旅程。', NULL, NULL, '2021-07-07', '[\"花江夏樹\",\"佐倉綾音\",\"鬼頭明里\",\"早見沙織\",\"辻親八\",\"久保ユリカ\",\"二ノ宮愛子\",\"上田麗奈\",\"前野智昭\",\"新祐樹\"]', '[\"花江夏樹\",\"佐倉綾音\",\"鬼頭明里\",\"早見沙織\",\"辻親八\",\"久保ユリカ\",\"二ノ宮愛子\",\"上田麗奈\",\"前野智昭\",\"新祐樹\",\"花江夏树\",\"佐仓绫音\",\"鬼头明里\",\"早见沙织\",\"辻亲八\",\"久保由利香\",\"二之宫爱子\",\"上田丽奈\",\"新祐树\"]', 1, '2026-02-10 00:03:33', '2026-03-18 18:01:55');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (145, '月光下的异世界之旅 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/3c/a5/350235_A0USf.jpg', 'completed', '7.4', 12, 12, NULL, '高中生深澄真被召唤到异世界成为勇者，却因外貌被女神嫌弃而流放至荒野。在第二季中，真继续在异世界建立自己的势力，与各种种族建立联系，同时面对来自女神和其他势力的威胁，逐渐揭开这个世界的真相。', '[\"异世界\",\"冒险\",\"奇幻\",\"战斗\"]', '高中生深澄真被召唤到异世界成为勇者，却因外貌被女神嫌弃而流放荒野。他凭借现代知识和契约伙伴的力量，在异世界展开冒险与成长之旅。第二季继续讲述他与伙伴们的新挑战和故事发展。', NULL, NULL, '2024-01-08', '[\"花江夏樹\",\"佐倉綾音\",\"鬼頭明里\",\"津田健次郎\",\"手塚ヒロミチ\",\"佐藤恵\",\"後藤ヒロキ\",\"佐久間元輝\",\"木南亜莉沙\",\"塩見宗真\"]', '[\"花江夏樹\",\"佐倉綾音\",\"鬼頭明里\",\"津田健次郎\",\"手塚ヒロミチ\",\"佐藤恵\",\"後藤ヒロキ\",\"佐久間元輝\",\"木南亜莉沙\",\"塩見宗真\",\"花江夏树\",\"佐仓绫音\",\"鬼头明里\",\"手冢宏道\",\"佐藤惠\",\"后藤宏树\",\"佐久间元辉\",\"木南亚莉沙\",\"盐见宗真\"]', 1, '2026-02-10 00:03:42', '2026-03-18 18:01:57');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (146, '别当欧尼酱了', 'お兄ちゃんはおしまい！', 'https://cdn.myanimelist.net/images/anime/1058/131632l.jpg', 'completed', '7.6', 12, 12, 24, '故事围绕高中生兄妹展开，哥哥是个成绩优秀但性格冷淡的天才，妹妹则是个活泼开朗的普通女孩。妹妹为了改变哥哥冷漠的性格，开始了一系列搞笑又温馨的“改造计划”，在校园和家庭生活中引发各种欢乐日常。通过妹妹的努力，兄妹关系逐渐改善，展现了亲情与成长的温暖故事。', '[\"校园\",\"喜剧\",\"日常\",\"亲情\",\"性转\",\"治愈\"]', '高中生高槻美优因意外事故变成了女孩，与妹妹高槻佳奈一起生活的日常喜剧故事。', NULL, '2026-02-08', '2023-01-05', '[\"れいみ\",\"高野麻里佳\",\"石原夏織\",\"さいとうよしえ\",\"金元寿子\",\"津田美波\",\"優木かな\",\"日岡なつみ\",\"青島れな\",\"阿部里果\"]', '[\"れいみ\",\"高野麻里佳\",\"石原夏織\",\"さいとうよしえ\",\"金元寿子\",\"津田美波\",\"優木かな\",\"日岡なつみ\",\"青島れな\",\"阿部里果\",\"玲美\",\"石原夏织\",\"斋藤千和\",\"优木加奈\",\"日冈夏美\",\"青岛丽奈\"]', 1, '2026-02-10 00:03:50', '2026-03-18 18:02:00');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (147, '这个治疗师有点烦', NULL, 'http://lain.bgm.tv/pic/cover/l/fd/d4/333176_E5Vcn.jpg', 'completed', NULL, 12, 12, NULL, '讲述新手治疗师阿尔文与性格恶劣的战士卡拉之间充满冲突的冒险故事。阿尔文虽然拥有强大的治疗能力，但性格软弱胆小；而卡拉则是个只追求战斗乐趣的麻烦战士。两人组成队伍后，阿尔文不仅要面对各种怪物，还要应付卡拉的任性要求，展开了一段既搞笑又温馨的异世界冒险旅程。', '[\"异世界\",\"搞笑\",\"冒险\",\"奇幻\"]', NULL, NULL, NULL, '2022-04-10', '[\"佐藤拓也\",\"大西亜玖璃\",\"泊明日菜\",\"白熊寛嗣\",\"速水奨\",\"早見沙織\",\"赤羽根健治\",\"久川綾\",\"佐倉綾音\",\"稲田徹\"]', '[\"佐藤拓也\",\"大西亜玖璃\",\"泊明日菜\",\"白熊寛嗣\",\"速水奨\",\"早見沙織\",\"赤羽根健治\",\"久川綾\",\"佐倉綾音\",\"稲田徹\",\"大西亚玖璃\",\"白熊宽嗣\",\"速水奖\",\"早见沙织\",\"久川绫\",\"佐仓绫音\",\"稻田彻\"]', 1, '2026-02-10 00:03:58', '2026-03-18 18:02:02');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (148, '莉可丽丝', NULL, 'http://lain.bgm.tv/pic/cover/l/65/19/364450_xx2zx.jpg', 'completed', '6.3', 13, 13, NULL, '在和平的日本，秘密组织“DA”培养少女特工“Lycoris”暗中维持治安。顶尖Lycoris锦木千束与问题队员井之上泷奈被分配到咖啡馆“Lycoris Recoil”分部。千束奉行不杀原则，而泷奈追求效率，两人在执行任务中逐渐磨合，共同面对威胁国家安全的阴谋与危机。', '[\"动作\",\"日常\",\"百合\",\"战斗\",\"原创动画\"]', '在东京的咖啡厅“LycoReco”中，表面上提供咖啡和甜点，实际上是由秘密组织“DA”派遣的少女特工们执行各种任务的故事。主角锦木千束和井之上泷奈在解决各种事件的同时，也面临着组织的阴谋和自身的命运。', NULL, NULL, '2022-07-02', '[\"安済知佳\",\"若山詩音\",\"小清水亜美\",\"久野美咲\",\"さかき孝輔\",\"上田燿司\",\"松岡禎丞\",\"榊原優希\",\"沢海陽子\",\"河瀬茉希\"]', '[\"安済知佳\",\"若山詩音\",\"小清水亜美\",\"久野美咲\",\"さかき孝輔\",\"上田燿司\",\"松岡禎丞\",\"榊原優希\",\"沢海陽子\",\"河瀬茉希\",\"安济知佳\",\"若山诗音\",\"小清水亚美\",\"榊孝辅\",\"上田耀司\",\"松冈祯丞\",\"榊原优希\",\"泽海阳子\",\"河濑茉希\"]', 1, '2026-02-10 00:04:05', '2026-03-18 18:02:05');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (149, '转生公主与天才千金的魔法革命', NULL, 'http://lain.bgm.tv/pic/cover/l/fd/3c/395714_5EeZx.jpg', 'completed', '7.5', 12, 12, NULL, '王女安妮丝菲亚因无法使用魔法而放弃王位继承权，转而沉迷于魔法道具研究。某天她邂逅了天才公爵千金尤菲莉亚，并因一场意外事件将尤菲从婚约中“绑架”。两人开始共同生活，安妮丝用自己开发的魔法道具帮助尤菲，而尤菲则展现出惊人的魔法天赋。这部作品讲述了两位少女在魔法世界中相互扶持、共同成长的奇幻故事。', '[\"奇幻\",\"百合\",\"魔法\",\"转生\",\"日常\"]', '转生为王国公主的艾妮丝菲亚，因无法使用魔法而沉迷于魔法道具研究。某天，她遇到了天才贵族千金尤菲莉亚，两人因魔法革命而命运交织，共同改变世界。', NULL, NULL, '2023-01-04', '[\"千本木彩花\",\"石見舞菜香\",\"加隈亜衣\",\"坂田将吾\",\"塚田悠衣\",\"篠原侑\",\"羊宮妃那\",\"浜田賢二\",\"小島幸子\",\"坪井智浩\"]', '[\"千本木彩花\",\"石見舞菜香\",\"加隈亜衣\",\"坂田将吾\",\"塚田悠衣\",\"篠原侑\",\"羊宮妃那\",\"浜田賢二\",\"小島幸子\",\"坪井智浩\",\"石见舞菜香\",\"加隈亚衣\",\"冢田悠衣\",\"筱原侑\",\"羊宫妃那\",\"滨田贤二\",\"小岛幸子\"]', 1, '2026-02-10 00:04:15', '2026-03-18 18:02:08');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (151, '安达与岛村', NULL, 'http://lain.bgm.tv/pic/cover/l/0f/a4/282372_pqp0S.jpg', 'completed', '5.9', 12, 12, NULL, '故事围绕两位高中女生安达与岛村展开。她们在体育馆二楼偶然相遇，从此开始了一段特别的友情。随着相处时间增多，两人关系逐渐变得微妙而复杂，安达发现自己对岛村产生了超越友谊的情感。这部作品细腻描绘了少女间青涩暧昧的情感变化与成长烦恼。', '[\"校园\",\"百合\",\"日常\",\"恋爱\"]', '高中女生安达与岛村是好朋友，她们经常一起逃课去体育馆二楼打发时间。随着相处，安达发现自己对岛村产生了超越友谊的感情，开始为这段关系感到困惑和不安。', NULL, NULL, '2020-10-08', '[\"鬼頭明里\",\"伊藤美来\",\"沼倉愛美\",\"上田麗奈\",\"佐伯伊織\",\"田中貴子\",\"茅野愛衣\",\"伊藤静\",\"川澄綾子\",\"佐藤利奈\"]', '[\"鬼頭明里\",\"伊藤美来\",\"沼倉愛美\",\"上田麗奈\",\"佐伯伊織\",\"田中貴子\",\"茅野愛衣\",\"伊藤静\",\"川澄綾子\",\"佐藤利奈\",\"鬼头明里\",\"沼仓爱美\",\"上田丽奈\",\"佐伯伊织\",\"田中贵子\",\"茅野爱衣\",\"川澄绫子\"]', 1, '2026-02-10 00:04:32', '2026-03-18 18:02:10');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (152, '恋爱实验室', NULL, 'https://cdn.myanimelist.net/images/anime/1900/147887l.jpg', 'completed', NULL, 12, 12, NULL, '故事发生在一所高中，学生们被要求参加一个名为“恋爱实验室”的特殊课程。在这个课程中，学生们必须通过科学实验的方式来探索和研究恋爱的本质。主角们组成小组，进行各种有趣的恋爱实验，从数据分析到实际互动，在欢笑与困惑中逐渐理解爱情的真谛。这部作品以轻松幽默的方式探讨青春期的情感问题。', '[\"校园\",\"恋爱\",\"喜剧\",\"日常\"]', '故事围绕五位高中女生展开，她们表面上看似完美，私下却进行着各种恋爱实验，以研究男性心理和恋爱行为。', NULL, NULL, '2013-07-04', '[\"沼倉愛美\",\"赤﨑千夏\",\"水瀬いのり\",\"佐倉綾音\",\"大地葉\",\"秋奈\",\"日高里菜\",\"諏訪彩花\",\"水島大宙\",\"松岡禎丞\"]', '[\"沼倉愛美\",\"赤﨑千夏\",\"水瀬いのり\",\"佐倉綾音\",\"大地葉\",\"秋奈\",\"日高里菜\",\"諏訪彩花\",\"水島大宙\",\"松岡禎丞\",\"沼仓爱美\",\"赤崎千夏\",\"水濑祈\",\"佐仓绫音\",\"大地叶\",\"诹访彩花\",\"水岛大宙\",\"松冈祯丞\"]', 1, '2026-02-10 00:04:40', '2026-03-18 18:02:13');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (153, '街角魔族 第三季', NULL, 'https://cdn.myanimelist.net/images/anime/1633/111518l.jpg', 'completed', NULL, 12, 12, NULL, '《街角魔族》第三季继续讲述普通女高中生吉田优子与魔族后裔暗黑魔法少女千代田桃之间的日常故事。优子为了解除家族诅咒而努力成为魔法少女，而桃则一边保护优子一边与她建立深厚友谊。本季中，两人将面对新的挑战，同时加深彼此的理解与羁绊，在轻松搞笑的日常中展现温暖人心的成长故事。', '[\"日常\",\"搞笑\",\"魔法少女\",\"校园\",\"治愈\"]', '《街角魔族》第三季继续讲述普通女高中生吉田优子与魔族少女千代田桃之间温馨有趣的日常故事。随着剧情发展，两人之间的羁绊不断加深，同时更多神秘角色登场，为这个充满魔法与欢笑的世界增添新的色彩。', NULL, NULL, NULL, '[]', NULL, 1, '2026-02-10 00:04:49', '2026-03-18 17:55:07');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (154, '摇曳百合 暑假时光！+', NULL, 'http://lain.bgm.tv/pic/cover/l/6b/d7/136311_N51T6.jpg', 'completed', '6.5', 2, 2, NULL, '《摇曳百合 暑假时光！+》是《摇曳百合》系列的两集OVA特别篇，延续了轻松愉快的日常风格。故事围绕娱乐部四位成员——赤座灯里、岁纳京子、船见结衣和吉川千夏，在暑假期间发生的各种趣事展开。从夏日祭典到海边游玩，再到社团活动室的日常闲聊，展现了少女们充满欢笑与温馨的暑假生活。', '[\"日常\",\"搞笑\",\"校园\",\"百合\",\"治愈\"]', '娱乐部成员们度过了一个充满欢笑和惊喜的暑假，在夏日祭典、海边旅行和日常活动中加深了彼此之间的友谊。', NULL, NULL, '2015-02-18', '[\"三上枝織\",\"大坪由佳\",\"津田美波\",\"大久保瑠美\",\"藤田咲\",\"豊崎愛生\",\"三森すずこ\",\"加藤英美里\",\"後藤沙緒里\",\"竹達彩奈\"]', '[\"三上枝織\",\"大坪由佳\",\"津田美波\",\"大久保瑠美\",\"藤田咲\",\"豊崎愛生\",\"三森すずこ\",\"加藤英美里\",\"後藤沙緒里\",\"竹達彩奈\",\"三上枝织\",\"丰崎爱生\",\"三森铃子\",\"后藤沙绪里\",\"竹达彩奈\"]', 1, '2026-02-10 00:04:58', '2026-03-18 18:02:20');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (155, '魔法禁书目录', NULL, 'http://lain.bgm.tv/pic/cover/l/76/6d/1014_nqAH8.jpg', 'completed', NULL, 24, 24, NULL, '在学园都市中，高中生上条当麻拥有能消除一切异能之力的右手“幻想杀手”。某天他遇见了从魔法世界逃来的修女茵蒂克丝，她体内被植入了十万三千本魔道书。为了保护茵蒂克丝并揭开学园都市与魔法世界的秘密，上条当麻卷入了科学与魔法的激烈冲突之中。', '[\"科幻\",\"魔法\",\"校园\",\"战斗\",\"超能力\"]', '在科学和魔法并存的世界里，高中生上条当麻拥有能消除一切超能力的右手“幻想杀手”。他遇到了从魔法世界逃出的修女茵蒂克丝，并卷入科学与魔法的冲突中。', NULL, NULL, '2008-10-04', '[\"阿部敦\",\"岡本信彦\",\"井口裕香\",\"佐藤利奈\",\"新井里美\",\"能登麻美子\",\"こやまきみこ\",\"甲斐田裕子\",\"伊藤静\",\"日高里菜\"]', '[\"阿部敦\",\"岡本信彦\",\"井口裕香\",\"佐藤利奈\",\"新井里美\",\"能登麻美子\",\"こやまきみこ\",\"甲斐田裕子\",\"伊藤静\",\"日高里菜\",\"冈本信彦\",\"小山喜美子\"]', 1, '2026-02-10 00:07:30', '2026-03-18 18:02:23');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (156, '某科学的超电磁炮', NULL, 'http://lain.bgm.tv/pic/cover/l/36/e7/2585_pn2eP.jpg', 'completed', NULL, 24, 24, NULL, '《魔法禁书目录》的外传作品，以学园都市中仅有的七名超能力者（Level 5）之一——御坂美琴为主角。故事围绕她与好友白井黑子、初春饰利、佐天泪子等人在学园都市的日常生活展开，描绘她们解决各种事件、对抗黑暗势力的冒险。作品以超能力战斗为核心，同时融入校园生活和友情元素，展现了美琴作为“超电磁炮”的强大实力与正义感。', '[\"校园\",\"战斗\",\"科幻\",\"超能力\",\"日常\"]', '在学园都市中，拥有电击能力的少女御坂美琴与朋友们一起解决各种事件，展现超能力者的日常生活与战斗。', NULL, NULL, '2009-10-02', '[\"佐藤利奈\",\"新井里美\",\"豊崎愛生\",\"伊藤かな恵\",\"阿部敦\",\"寿美菜子\",\"遠藤綾\",\"戸松遥\",\"南條愛乃\",\"植田佳奈\"]', '[\"佐藤利奈\",\"新井里美\",\"豊崎愛生\",\"伊藤かな恵\",\"阿部敦\",\"寿美菜子\",\"遠藤綾\",\"戸松遥\",\"南條愛乃\",\"植田佳奈\",\"丰崎爱生\",\"伊藤加奈惠\",\"远藤绫\",\"户松遥\",\"南条爱乃\"]', 1, '2026-02-10 00:07:38', '2026-03-18 18:02:26');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (157, '某科学的一方通行', NULL, 'http://lain.bgm.tv/pic/cover/l/3f/11/262939_ZhtWQ.jpg', 'completed', '7.2', 12, 12, NULL, '《某科学的超电磁炮》的外传作品，聚焦于学园都市最强超能力者一方通行。故事讲述他在与最后之作相遇后，为了保护这个被他伤害过的少女，与各种威胁对抗。一方通行在失去大部分能力后，运用智慧和仅存的力量，在黑暗的学园都市中守护重要之人，展现他复杂而深刻的内心转变。', '[\"科幻\",\"战斗\",\"校园\",\"超能力\",\"黑暗\"]', '在学园都市中，拥有最强超能力的一方通行与最后之作相遇，为了保护她而卷入各种事件，逐渐改变自己的生活方式。', NULL, '2026-02-09', '2019-07-12', '[\"岡本信彦\",\"日高里菜\",\"久保ユリカ\",\"甲斐田裕子\",\"ささきのぞみ\",\"冬馬由美\",\"仲野裕\",\"渡部紗弓\",\"逢坂良太\",\"真野あゆみ\"]', '[\"岡本信彦\",\"日高里菜\",\"久保ユリカ\",\"甲斐田裕子\",\"ささきのぞみ\",\"冬馬由美\",\"仲野裕\",\"渡部紗弓\",\"逢坂良太\",\"真野あゆみ\",\"冈本信彦\",\"久保由利香\",\"佐佐木望\",\"冬马由美\",\"渡部纱弓\",\"真野步\"]', 1, '2026-02-10 00:07:47', '2026-03-18 18:02:29');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (158, '魔法禁书目录 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/8d/91/7843_KPkpp.jpg', 'completed', NULL, 24, 24, NULL, '故事继续围绕拥有能消除一切异能之力的右手少年上条当麻展开。第二季中，当麻与魔法侧和科学侧的势力继续产生交集，面对新的敌人和挑战。主要剧情包括“法之书事件”、“大霸星祭篇”和“C文书事件”，揭示了魔法与科学两大阵营背后更深的阴谋与冲突。', '[\"校园\",\"战斗\",\"奇幻\",\"科幻\"]', '《魔法禁书目录》第二季继续讲述上条当麻在学园都市的冒险故事。本季中，当麻将面对新的敌人和挑战，包括与罗马正教的冲突、魔法结社的阴谋，以及更多关于魔法与科学交织的复杂事件。故事深入探讨了魔法与科学之间的对立与融合，以及当麻如何运用他的右手能力“幻想杀手”来保护身边的人。', NULL, NULL, '2010-10-08', '[\"阿部敦\",\"岡本信彦\",\"井口裕香\",\"佐藤利奈\",\"新井里美\",\"能登麻美子\",\"こやまきみこ\",\"豊崎愛生\",\"甲斐田裕子\",\"伊藤静\"]', '[\"阿部敦\",\"岡本信彦\",\"井口裕香\",\"佐藤利奈\",\"新井里美\",\"能登麻美子\",\"こやまきみこ\",\"豊崎愛生\",\"甲斐田裕子\",\"伊藤静\",\"冈本信彦\",\"小山喜美子\",\"丰崎爱生\"]', 1, '2026-02-10 00:09:09', '2026-03-18 18:02:32');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (159, '魔法禁书目录 第三季', NULL, 'http://lain.bgm.tv/pic/cover/l/22/f2/26804_yV6qZ.jpg', 'completed', NULL, 26, 26, NULL, '《魔法禁书目录》第三季继续讲述上条当麻的故事。在学园都市中，当麻的右手“幻想杀手”能消除一切异能之力。本季中，当麻将面对来自魔法侧的新威胁，包括英国清教与罗马正教的冲突，以及“神之右席”成员的登场。同时，科学侧的暗部组织“集团”也展开行动，当麻必须在魔法与科学的夹缝中保护身边的人，揭开隐藏在学园都市背后的更大阴谋。', '[\"科幻\",\"战斗\",\"校园\",\"超能力\",\"魔法\"]', '《魔法禁书目录》第三季继续讲述上条当麻在科学与魔法交织的世界中的冒险故事。本季主要围绕英国清教与罗马正教的冲突展开，涉及“C文书”事件和“法之书”事件，同时深入探索魔法侧与科学侧的复杂关系。', NULL, NULL, '2018-10-05', '[\"井口裕香\",\"阿部敦\",\"佐藤利奈\",\"岡本信彦\",\"日野聡\",\"新井里美\",\"能登麻美子\",\"こやまきみこ\",\"豊崎愛生\",\"甲斐田裕子\"]', '[\"井口裕香\",\"阿部敦\",\"佐藤利奈\",\"岡本信彦\",\"日野聡\",\"新井里美\",\"能登麻美子\",\"こやまきみこ\",\"豊崎愛生\",\"甲斐田裕子\",\"冈本信彦\",\"日野聪\",\"小山喜美子\",\"丰崎爱生\"]', 1, '2026-02-10 00:10:02', '2026-03-18 18:02:35');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (160, '某科学的超电磁炮 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/99/8c/51928_wuG5D.jpg', 'completed', '7.4', 24, 24, NULL, '《某科学的超电磁炮 第二季》以学园都市为背景，讲述了御坂美琴（超电磁炮）与白井黑子等风纪委员的日常故事。本季主要围绕“妹妹们”事件展开，美琴得知学园都市的“绝对能力者进化计划”后，决心阻止实验并拯救被用作实验体的克隆人“御坂妹妹”。剧情涉及科学实验、超能力战斗以及友情与正义的探讨，展现了美琴坚强勇敢的一面。', '[\"科幻\",\"校园\",\"战斗\",\"超能力\"]', '学园都市中，拥有电击能力的御坂美琴卷入了一场涉及克隆人实验的阴谋，她必须面对自己的克隆体并阻止危险的实验计划。', NULL, NULL, '2013-04-12', '[\"Zhang, Huilin\",\"He, Wenxiao\"]', '[\"Zhang, Huilin\",\"He, Wenxiao\",\"张惠霖\",\"何文晓\"]', 1, '2026-02-10 00:10:11', '2026-03-18 18:02:39');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (161, '黑色四叶草', NULL, 'http://lain.bgm.tv/pic/cover/l/e5/a5/202880_f45cZ.jpg', 'completed', '7.3', 170, 170, NULL, '在一个魔法决定一切的世界，亚斯塔虽天生没有魔力却梦想成为魔法帝。他偶然获得反魔法能力的五叶草魔导书，与天才魔法师尤诺一同加入魔法骑士团。两人在对抗邪恶势力、保护王国的冒险中不断成长，亚斯塔凭借不屈意志挑战命运，证明即使没有魔力也能成为最强魔法骑士。', '[\"热血\",\"奇幻\",\"战斗\",\"冒险\",\"少年\"]', '在一个魔法决定一切的世界里，天生没有魔力的少年亚斯塔立志成为魔法帝，与拥有强大魔力的同伴尤诺一起加入魔法骑士团，展开热血冒险。', NULL, NULL, '2017-10-03', '[\"梶原岳人\",\"藤田奈央\",\"島﨑信長\",\"関根有咲\",\"優木かな\",\"諏訪部順一\",\"福山潤\",\"室元気\",\"村瀬歩\",\"日野聡\"]', '[\"梶原岳人\",\"藤田奈央\",\"島﨑信長\",\"関根有咲\",\"優木かな\",\"諏訪部順一\",\"福山潤\",\"室元気\",\"村瀬歩\",\"日野聡\",\"岛崎信长\",\"关根有咲\",\"优木加奈\",\"诹访部顺一\",\"福山润\",\"室元气\",\"村濑步\",\"日野聪\"]', 1, '2026-02-10 00:11:28', '2026-03-18 18:02:44');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (162, '里亚德录大地', NULL, 'http://lain.bgm.tv/pic/cover/l/d9/eb/329014_660vh.jpg', 'completed', '7.0', 12, 12, NULL, '故事讲述因事故陷入昏迷的少女加贺道夫，在VRMMO游戏《里亚德录》中以高等精灵“葵娜”的身份醒来，却发现游戏世界已过去200年。她在这个熟悉又陌生的世界里，一边寻找其他玩家，一边运用自己满级的技能和知识，逐渐融入新生活，并与NPC们建立起深厚的羁绊，展开一段温馨又充满冒险的异世界旅程。', '[\"异世界\",\"游戏\",\"冒险\",\"日常\",\"奇幻\"]', '一名在现实世界去世的少女，在200年后于游戏世界「里亚德录」中苏醒，以高等精灵「葵娜」的身份展开新生活，探索这个熟悉又陌生的世界。', NULL, NULL, '2022-01-05', '[\"幸村恵理\",\"小野大輔\",\"名塚佳織\",\"杉田智和\",\"小田切優衣\",\"柳原かなこ\",\"中村桜\",\"広瀬ゆうき\",\"田所あずさ\",\"髙木朋弥\"]', '[\"幸村恵理\",\"小野大輔\",\"名塚佳織\",\"杉田智和\",\"小田切優衣\",\"柳原かなこ\",\"中村桜\",\"広瀬ゆうき\",\"田所あずさ\",\"髙木朋弥\",\"幸村惠理\",\"小野大辅\",\"名冢佳织\",\"小田切优衣\",\"柳原香奈子\",\"中村樱\",\"广濑佑希\",\"田所梓\",\"高木朋弥\"]', 1, '2026-02-10 00:11:38', '2026-03-18 18:02:46');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (163, '天才王子的赤字国家振兴术', NULL, 'https://cdn.myanimelist.net/images/anime/1263/119511l.jpg', 'completed', '7.4', 12, 12, NULL, '维恩·萨雷玛·阿尔巴斯特是纳特拉王国的年轻王子，他统治着一个贫穷弱小的国家。面对邻国的威胁和国内的财政赤字，维恩制定了一个大胆的计划：将国家卖给邻国以换取巨额财富，然后退休享受奢华生活。然而，他的天才策略总是意外地让国家变得更加强大和繁荣，导致他的卖国计划一次次失败。', '[\"奇幻\",\"政治\",\"喜剧\",\"轻小说改编\"]', '天才王子维恩为了摆脱财政赤字，试图卖掉自己的国家，却意外地让国家变得越来越强大。', NULL, NULL, '2022-01-11', '[\"斉藤壮馬\",\"高橋李依\",\"千本木彩花\",\"東山奈央\",\"日笠陽子\",\"榊原優希\",\"中島由貴\",\"菅生隆之\",\"濱野大輝\",\"大塚明夫\"]', '[\"斉藤壮馬\",\"高橋李依\",\"千本木彩花\",\"東山奈央\",\"日笠陽子\",\"榊原優希\",\"中島由貴\",\"菅生隆之\",\"濱野大輝\",\"大塚明夫\",\"齐藤壮马\",\"斋藤壮马\",\"高桥李依\",\"东山奈央\",\"日笠阳子\",\"榊原优希\",\"中岛由贵\",\"滨野大辉\",\"大冢明夫\"]', 1, '2026-02-10 00:11:47', '2026-03-18 18:02:49');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (164, '间谍过家家 第一季', NULL, 'http://lain.bgm.tv/pic/cover/l/de/4a/329906_hmtVD.jpg', 'completed', NULL, 25, 25, NULL, '西国顶尖间谍“黄昏”奉命组建虚假家庭潜入名校，意外收养能读心的超能力女儿阿尼亚，并与伪装成公务员的杀手约尔假结婚。三人互相隐瞒真实身份，在危机四伏的间谍任务与温馨日常中，逐渐产生真挚的亲情羁绊。', '[\"喜剧\",\"动作\",\"家庭\",\"校园\"]', '西国顶尖间谍“黄昏”为了执行秘密任务，组建了一个临时家庭，却意外发现收养的女儿拥有读心能力，而妻子竟是职业杀手。三人互相隐瞒真实身份，共同生活的温馨搞笑故事。', NULL, NULL, '2025-10-04', '[\"江口拓也\",\"津田美波\",\"早見沙織\",\"種﨑敦美\",\"松田健一郎\",\"藤原夏海\",\"加藤英美里\",\"佐倉綾音\",\"山路和弘\",\"小野賢章\"]', '[\"江口拓也\",\"津田美波\",\"早見沙織\",\"種﨑敦美\",\"松田健一郎\",\"藤原夏海\",\"加藤英美里\",\"佐倉綾音\",\"山路和弘\",\"小野賢章\",\"早见沙织\",\"种崎敦美\",\"佐仓绫音\",\"小野贤章\"]', 1, '2026-02-10 00:13:45', '2026-03-18 18:02:51');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (165, '葬送的芙莉莲 第一季', '葬送のフリーレン', 'http://lain.bgm.tv/pic/cover/l/13/c5/400602_ZI8Y9.jpg', 'watching', '9.3', 1, 28, 24, '故事讲述精灵魔法使芙莉莲与勇者一行击败魔王后，在漫长的岁月中逐渐理解人类情感。五十年后勇者离世，芙莉莲开始重新审视生命意义，踏上收集魔法、了解人类的旅程。通过回忆与现实的交织，展现时间、记忆与羁绊的深刻主题。', '[\"奇幻\",\"冒险\",\"治愈\",\"剧情\"]', '在击败魔王后，精灵魔法使芙莉莲与同伴们踏上了长达十年的冒险旅程。然而，对于拥有漫长寿命的精灵来说，十年只是短暂一瞬。在勇者辛美尔去世后，芙莉莲开始反思自己与人类同伴共度的时光，决定重新踏上旅程，去更深入地了解人类的情感与记忆。', NULL, NULL, '2023-09-29', '[\"種﨑敦美\",\"李蝉妃\",\"李昀晴\",\"市ノ瀬加那\",\"林沛笭\",\"苏婉\",\"清都ありさ\",\"小林千晃\",\"邱涵菲\",\"張立昂\"]', '[\"種﨑敦美\",\"李蝉妃\",\"李昀晴\",\"市ノ瀬加那\",\"林沛笭\",\"苏婉\",\"清都ありさ\",\"小林千晃\",\"邱涵菲\",\"張立昂\",\"种崎敦美\",\"市之濑加那\",\"清都亚理沙\",\"张立昂\"]', 1, '2026-02-10 00:13:53', '2026-03-18 18:02:54');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (166, '转生成蜘蛛又怎样！', NULL, 'http://lain.bgm.tv/pic/cover/l/83/73/252782_aWyEn.jpg', 'completed', '5.8', 24, 24, NULL, '一名普通女高中生转生到异世界，发现自己变成了最弱小的蜘蛛魔物。为了在充满危险的迷宫中生存，她必须运用前世的知识和蜘蛛的本能不断进化。故事以幽默又残酷的方式，展现她从底层魔物逐渐成长为强大存在的奋斗历程，同时揭露这个异世界背后的惊人秘密。', '[\"异世界\",\"转生\",\"冒险\",\"奇幻\",\"战斗\"]', '一名普通女高中生转生为蜘蛛魔物，在危险的地下迷宫中努力生存并变强的异世界冒险故事。', NULL, NULL, '2021-01-08', '[\"悠木碧\",\"早見沙織\",\"堀江瞬\",\"東山奈央\",\"石川界人\",\"小倉唯\",\"喜多村英梨\",\"奥野香耶\",\"田中あいみ\",\"榎木淳弥\"]', '[\"悠木碧\",\"早見沙織\",\"堀江瞬\",\"東山奈央\",\"石川界人\",\"小倉唯\",\"喜多村英梨\",\"奥野香耶\",\"田中あいみ\",\"榎木淳弥\",\"早见沙织\",\"东山奈央\",\"小仓唯\",\"田中爱美\"]', 1, '2026-02-10 00:18:02', '2026-03-18 18:02:56');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (167, '打了三百年史莱姆，不知不觉就练到了满级', NULL, 'http://lain.bgm.tv/pic/cover/l/01/e4/292969_dUxlx.jpg', 'completed', NULL, 12, 12, NULL, '因过度劳累而离世的上班族相泽梓，转生到异世界成为不老不死的魔女亚梓莎。她决定过上悠闲的慢生活，每天只打25只史莱姆。然而持续了300年后，她不知不觉中达到了满级，成为了传说中的“高原魔女”，平静的生活也因此被打破。', '[\"异世界\",\"日常\",\"喜剧\",\"奇幻\",\"转生\"]', '一名普通上班族因过劳去世后转生为不老不死的魔女，在边境悠闲生活了300年，每天打倒史莱姆赚取生活费，不知不觉中竟练到了满级。', NULL, NULL, '2021-04-10', '[\"悠木碧\",\"和氣あず未\",\"杉山里穂\",\"本渡楓\",\"千本木彩花\",\"田中美海\",\"原田彩楓\",\"沼倉愛美\",\"小岩井ことり\",\"井上喜久子\"]', '[\"悠木碧\",\"和氣あず未\",\"杉山里穂\",\"本渡楓\",\"千本木彩花\",\"田中美海\",\"原田彩楓\",\"沼倉愛美\",\"小岩井ことり\",\"井上喜久子\",\"和气杏未\",\"杉山里穗\",\"本渡枫\",\"原田彩枫\",\"沼仓爱美\",\"小岩井小鸟\"]', 1, '2026-02-10 00:22:19', '2026-03-18 18:02:59');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (168, '因为太怕痛就全点防御力了。 第二季', NULL, 'http://lain.bgm.tv/pic/cover/l/a5/3c/302766_Vqzpu.jpg', 'completed', '7.4', 12, 12, NULL, '梅普露在VRMMO游戏《NewWorld Online》中继续她的冒险之旅。第二季中，她与好友莎莉一起探索新区域、挑战更强敌人，并参与大型公会活动。梅普露凭借其独特的防御型技能和意外获得的强大能力，在游戏中不断创造奇迹，同时与更多玩家建立友谊，共同面对游戏中的各种挑战。', '[\"游戏\",\"冒险\",\"喜剧\",\"奇幻\",\"日常\"]', '在VRMMO游戏《NewWorld Online》中，新手玩家梅普露继续她的冒险。凭借全点防御力的独特玩法，她获得了各种强大的防御技能和装备，与好友莎莉一起探索游戏世界，面对新的挑战和敌人。', NULL, NULL, '2023-01-11', '[\"本渡楓\",\"野口瑠璃子\",\"杉山紀彰\",\"佐藤聡美\",\"早見沙織\",\"新井里美\",\"加隈亜衣\",\"諏訪ななか\",\"島袋美由利\",\"松井暁波\"]', '[\"本渡楓\",\"野口瑠璃子\",\"杉山紀彰\",\"佐藤聡美\",\"早見沙織\",\"新井里美\",\"加隈亜衣\",\"諏訪ななか\",\"島袋美由利\",\"松井暁波\",\"本渡枫\",\"杉山纪彰\",\"佐藤聪美\",\"早见沙织\",\"加隈亚衣\",\"诹访奈奈香\",\"岛袋美由利\",\"松井晓波\"]', 1, '2026-02-10 23:19:46', '2026-03-18 18:03:01');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (171, '葬送的芙莉莲 第二季', '葬送的芙莉莲 第二季', 'https://lain.bgm.tv/pic/cover/l/0b/24/515759_qA1Zc.jpg', 'watching', '7.4', 0, 28, 24, '在勇者辛美尔去世后，精灵魔法使芙莉莲与同伴们继续踏上收集魔法的旅程。第二季延续了芙莉莲对生命意义的探索，通过回忆与现实的交织，展现她与人类同伴之间跨越时光的深厚羁绊。随着旅程深入，芙莉莲逐渐理解人类情感，并面对更强大的敌人与魔法挑战。', '[\"奇幻\",\"冒险\",\"治愈\",\"剧情\"]', '魔法使芙莉莲与勇者一行击败魔王后，踏上收集魔法的旅程，探索生命与时间的意义。', NULL, NULL, '2026-01-16', '[\"種﨑敦美\",\"市ノ瀬加那\",\"清都ありさ\",\"小林千晃\",\"岡本信彦\",\"東地宏樹\",\"上田燿司\",\"新垣樽助\",\"谷山紀章\",\"村井雄治\"]', '[\"種﨑敦美\",\"市ノ瀬加那\",\"清都ありさ\",\"小林千晃\",\"岡本信彦\",\"東地宏樹\",\"上田燿司\",\"新垣樽助\",\"谷山紀章\",\"村井雄治\",\"种崎敦美\",\"市之濑加那\",\"清都亚理沙\",\"冈本信彦\",\"东地宏树\",\"上田耀司\",\"谷山纪章\"]', 0, '2026-02-15 12:34:29', '2026-03-18 18:03:04');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (175, 'Re:Stage！Dream Days♪', 'Re:ステージ！ドリームデイズ♪', 'http://lain.bgm.tv/pic/cover/l/65/6d/252321_6JO8N.jpg', 'watching', '6.7', 2, 12, 24, '故事围绕着一群热爱舞台表演的少女展开，她们在“私立稀星学园高尾校”相遇，共同追求成为顶尖偶像的梦想。通过日常训练、友情互动和舞台挑战，少女们逐渐成长，面对竞争与困难，最终在闪耀的舞台上绽放光芒。作品融合了校园生活、音乐表演和青春励志元素，展现了少女们追逐梦想的动人故事。', '[\"校园\",\"音乐\",\"偶像\",\"日常\",\"励志\",\"青春\"]', '讲述一群高中女生组成偶像团体，在音乐与舞蹈中追逐梦想的故事。', '2026-03-02', NULL, '2019-07-07', '[\"牧野天音\",\"鬼頭明里\",\"田澤茉純\",\"立花芽恵夢\",\"岩橋由佳\",\"空見ゆき\",\"小澤亜李\",\"花守ゆみり\",\"髙橋ミナミ\",\"諏訪彩花\"]', '[\"牧野天音\",\"鬼頭明里\",\"田澤茉純\",\"立花芽恵夢\",\"岩橋由佳\",\"空見ゆき\",\"小澤亜李\",\"花守ゆみり\",\"髙橋ミナミ\",\"諏訪彩花\",\"鬼头明里\",\"田泽茉纯\",\"立花芽惠梦\",\"岩桥由佳\",\"空见雪\",\"小泽亚李\",\"花守由美里\",\"高桥美波\",\"诹访彩花\"]', 1, '2026-03-02 00:41:37', '2026-03-18 18:03:08');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (176, '摇曳露营△ 剧场版', NULL, 'http://lain.bgm.tv/pic/cover/l/40/19/262898_NSwWq.jpg', 'completed', NULL, 1, 1, NULL, '本作是《摇曳露营△》系列的首部剧场版动画，讲述了高中毕业后的各务原抚子与志摩凛等露营伙伴们，为了实现“环游伊豆半岛一周”的梦想而展开的特别旅程。在旅途中，她们不仅欣赏到伊豆半岛的壮丽自然风光，还遇到了新的露营爱好者，共同体验户外生活的乐趣与挑战，加深了彼此间的羁绊。', '[\"日常\",\"治愈\",\"露营\",\"旅行\",\"友情\"]', '五位热爱露营的少女在高中毕业后，各自踏上不同的人生道路，但她们依然通过露营保持联系。某天，她们决定一起规划一次特别的露营旅行，重温过去的友谊与美好时光。', NULL, NULL, '2022-07-01', '[]', NULL, 1, '2026-03-09 14:13:45', '2026-03-18 18:03:13');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (179, '间谍过家家 第三季', 'SPY×FAMILY Season 3', 'https://lain.bgm.tv/pic/cover/l/3d/79/498378_3ycrL.jpg', 'watching', '8.2', 7, 13, NULL, NULL, '[\"校园\",\"喜剧\",\"动作\",\"家庭\"]', NULL, '2026-03-12', NULL, '2025-10-04', '[\"江口拓也\",\"津田美波\",\"早見沙織\",\"種﨑敦美\",\"松田健一郎\",\"藤原夏海\",\"加藤英美里\",\"佐倉綾音\",\"山路和弘\",\"小野賢章\"]', '[\"江口拓也\",\"津田美波\",\"早見沙織\",\"種﨑敦美\",\"松田健一郎\",\"藤原夏海\",\"加藤英美里\",\"佐倉綾音\",\"山路和弘\",\"小野賢章\",\"早见沙织\",\"种崎敦美\",\"佐仓绫音\",\"小野贤章\",\"冯泽锐\",\"三石\",\"段艺璇\",\"斑马\",\"康潇文\",\"家明\",\"赵哲豪\",\"袁铭喆\",\"唐策\",\"周侗\"]', 1, '2026-03-17 00:57:08', '2026-03-20 02:44:51');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (181, '放学后海堤日记', '放課後ていぼう日誌', 'https://lain.bgm.tv/pic/cover/l/97/b6/280678_rQ75K.jpg', 'completed', '7.5', 12, 12, 24, NULL, '[\"校园\",\"喜剧\",\"日常\",\"钓鱼\"]', '故事讲述高中生海野雫加入学校钓鱼社后，与社员们一起享受钓鱼乐趣的日常校园生活。', '2026-03-17', '2026-03-17', '2020-04-07', '[\"高尾奏音\",\"川井田夏海\",\"篠原侑\",\"明坂聡美\",\"小清水亜美\",\"斎藤千和\",\"早水リサ\"]', '[\"高尾奏音\",\"川井田夏海\",\"篠原侑\",\"明坂聡美\",\"小清水亜美\",\"斎藤千和\",\"早水リサ\",\"明坂聪美\",\"小清水亚美\",\"斋藤千和\",\"早水丽莎\"]', 1, '2026-03-18 00:19:16', '2026-03-18 18:03:23');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (182, '看得见的女孩', '阴阳眼见子', 'https://lain.bgm.tv/pic/cover/l/bc/6b/330973_HpbMw.jpg', 'completed', NULL, 12, 12, 24, NULL, '[\"校园\",\"喜剧\",\"恐怖\",\"超自然\"]', '高中生四谷见子突然获得了看见鬼怪的能力，她必须假装看不见这些恐怖的存在，同时寻找生存之道。', '2026-03-17', '2026-03-17', '2021-10-03', '[\"雨宮天\",\"本渡楓\",\"佐倉綾音\",\"寺崎裕香\",\"中村悠一\",\"谷育子\",\"花守ゆみり\",\"鳥海浩輔\",\"生天目仁美\",\"杉山里穂\"]', '[\"雨宮天\",\"本渡楓\",\"佐倉綾音\",\"寺崎裕香\",\"中村悠一\",\"谷育子\",\"花守ゆみり\",\"鳥海浩輔\",\"生天目仁美\",\"杉山里穂\",\"雨宫天\",\"本渡枫\",\"佐仓绫音\",\"花守由美里\",\"鸟海浩辅\",\"杉山里穗\"]', 1, '2026-03-18 00:41:44', '2026-03-18 18:03:26');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (183, '我心里危险的东西 第二季', 'Boku no Kokoro no Yabai Yatsu Season 1', 'https://lain.bgm.tv/pic/cover/l/ba/7e/441795_q6Sc3.jpg', 'completed', '8.7', 12, 12, 24, NULL, '[\"校园\",\"喜剧\",\"恋爱\"]', '讲述一个内心阴暗的初中男生与开朗活泼的同班女生之间逐渐发展的青春恋爱喜剧故事。', NULL, NULL, '2024-01-06', '[\"羊宮妃那\",\"堀江瞬\",\"朝井彩加\",\"潘めぐみ\",\"種﨑敦美\",\"岡本信彦\",\"佐藤元\",\"福島潤\",\"豊崎愛生\",\"田村ゆかり\"]', '[\"羊宮妃那\",\"堀江瞬\",\"朝井彩加\",\"潘めぐみ\",\"種﨑敦美\",\"岡本信彦\",\"佐藤元\",\"福島潤\",\"豊崎愛生\",\"田村ゆかり\",\"羊宫妃那\",\"潘惠美\",\"种崎敦美\",\"冈本信彦\",\"福岛润\",\"丰崎爱生\",\"田村由香里\"]', 1, '2026-03-18 00:42:01', '2026-03-18 18:03:31');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (184, '南家三姐妹 欢迎回来', NULL, 'http://lain.bgm.tv/pic/cover/l/07/87/889_qF2Qq.jpg', 'completed', NULL, 13, 13, NULL, '《南家三姐妹 欢迎回来》是《南家三姐妹》系列的第四季动画，继续讲述南家三姐妹春香、夏奈和千秋的日常生活。本季中，三姐妹与朋友们在学校和家中发生各种轻松有趣的日常故事，展现了她们之间深厚的姐妹情谊和青春期的点滴成长。动画延续了系列一贯的温馨搞笑风格，通过细腻的日常描写，让观众感受到平凡生活中的温暖与欢乐。', '[\"校园\",\"日常\",\"喜剧\",\"姐妹\",\"二刷\"]', '南家三姐妹的日常生活继续，春香、夏奈和千秋三姐妹与朋友们一起度过温馨有趣的时光，展现了家庭亲情和青春成长的点点滴滴。', NULL, NULL, '2009-01-03', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"柿原徹也\",\"浅沼晋太郎\",\"喜多村英梨\",\"森永理科\",\"豊崎愛生\",\"後藤沙緒里\"]', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"柿原徹也\",\"浅沼晋太郎\",\"喜多村英梨\",\"森永理科\",\"豊崎愛生\",\"後藤沙緒里\",\"茅原实里\",\"水树奈奈\",\"柿原彻也\",\"丰崎爱生\",\"后藤沙绪里\"]', 1, '2026-03-18 21:08:57', '2026-03-18 21:08:57');
INSERT INTO `anime` (`id`, `title`, `original_title`, `coverUrl`, `status`, `score`, `progress`, `totalEpisodes`, `durationMinutes`, `notes`, `tags`, `summary`, `start_date`, `end_date`, `premiere_date`, `cast`, `cast_aliases`, `isFinished`, `createdAt`, `updatedAt`) VALUES (185, '南家三姐妹 我回来了', 'みなみけ ただいま', 'https://lain.bgm.tv/pic/cover/l/6e/1b/47685_QC42y.jpg', 'completed', '7.6', 13, 13, 24, NULL, '[\"校园\",\"喜剧\",\"日常\"]', '南家三姐妹——春香、夏奈、千秋的日常生活喜剧，围绕她们的校园和家庭趣事展开，充满轻松幽默的氛围。', NULL, NULL, '2013-01-05', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"高木礼子\",\"小野涼子\",\"小野大輔\",\"吉野裕行\",\"齋藤彩夏\",\"千葉紗子\"]', '[\"佐藤利奈\",\"井上麻里奈\",\"茅原実里\",\"水樹奈々\",\"高木礼子\",\"小野涼子\",\"小野大輔\",\"吉野裕行\",\"齋藤彩夏\",\"千葉紗子\",\"茅原实里\",\"水树奈奈\",\"小野凉子\",\"小野大辅\",\"斋藤彩夏\",\"千叶纱子\"]', 1, '2026-03-18 21:09:14', '2026-03-18 21:09:14');
